import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
// V10.2.0: Firestore RETIRED. Supabase is now the only cloud backend.
//   Removed imports: 'firebase/app', 'firebase/firestore'. The Firebase package
//   may still be in package.json but is no longer imported or used at runtime.
//   Was a parallel-write backend during Sessions 1-2; now fully removed in Session 3+4.
import { createClient as createSupabaseClient } from '@supabase/supabase-js';

// ═══════════════════════════════════════
// V5.6: FIRESTORE SYNC LAYER
// ═══════════════════════════════════════
// Cloud-backed persistence for Tara. Fixes the "refresh-roulette" problem where Tara's Call
// and the engine lock both reset on page reload because they lived only in React refs.
//
// Model: localStorage stays as the fast-paint cache so first paint is instant. Firestore
// is the source of truth — its read overwrites local state ~200-500ms after mount when
// fresher data exists. Writes go to both stores (localStorage immediately, Firestore
// debounced 300-1500ms depending on path).
//
// V5.6.3: SHARED TARA. Previously every userId was its own namespace. Now there is one
// global Tara — every browser, every device, every user who opens the app sees the same
// record, the same memory, the same lock state. Paths are 2-segment globals.
//
// Paths (global, no namespace):
//   state/currentLock     → engine lockedCallRef + Tara snapshot for the active window.
//                           windowId-keyed so a refresh during the same window restores
//                           exactly what was on screen before reload. Stale locks from
//                           previous windows are ignored on restore.
//   scorecards/tara       → Tara's Call W/L/sitouts per window-type.
//   memory/taraCallLog    → array of every call she's made (capped at 500).
//   meta/info             → baselineVersion + lastSeenAt for migration tracking.
//
// NOT cloud-synced (per V5.5b decision — user-trade-driven training stays ephemeral):
//   adaptiveWeights, regimeWeights, tradeLog. These remain in-memory only this session.
//
// Test-mode caveat: Firestore rules are wide open for ~30 days. Lock down in V5.7 with
// proper rules.
const FIREBASE_CONFIG=null; // V10.2.0: retired. Kept declared to avoid breaking any leftover references; set to null permanently.
let _fbApp=null,_fbDb=null; // V10.2.0: permanently null. All cloud ops now route through Supabase. See `_sbClient` below.

// ═══════════════════════════════════════════════════════════════════════════
// V10.1.0 — SUPABASE MIGRATION SPEC (locked 2026-05-14)
// ═══════════════════════════════════════════════════════════════════════════
//
// MOTIVATION
//   Firestore free tier (50K reads/day, 20K writes/day) hit quota repeatedly
//   on 2026-05-14 due to taraWeights / regimeMemory / pastWindows writes
//   firing on every state change. RMW transactions count both a read AND a
//   write per call, so the actual quota burn was ~2x the visible write rate.
//   Symptoms: 'resource-exhausted' errors, cross-device sync silently dropping
//   updates, baseline drift between devices.
//
//   Supabase free tier offers 500MB Postgres + unlimited API calls (measured
//   in egress, not request count) which is far more generous for our use case.
//   This migration moves all cloud sync from Firestore to Supabase while
//   preserving the existing "Shared Tara" model (no auth, cross-device,
//   cross-user — anyone with the deployment URL sees the same data).
//
// SCOPE
//   IN: All 6 Firestore paths get migrated to Supabase:
//       memory/taraCallLog        → tara_state row, doc_path='memory/taraCallLog'
//       state/lifetimePnL         → tara_state row, doc_path='state/lifetimePnL'
//       history/pastWindows       → tara_state row, doc_path='history/pastWindows'
//       learnings/tara            → tara_state row, doc_path='learnings/tara'
//       learnings/regimeMemory    → tara_state row, doc_path='learnings/regimeMemory'
//       learnings/taraWeights     → tara_state row, doc_path='learnings/taraWeights'
//       baseline/canonical        → tara_state row, doc_path='baseline/canonical'
//       state/currentLock         → tara_state row, doc_path='state/currentLock'
//       scorecards/tara           → tara_state row, doc_path='scorecards/tara'
//       meta/info                 → tara_state row, doc_path='meta/info'
//
//   ALSO IN: localStorage keys that benefit from cross-device sync:
//       tara_autoexec_v1, tara_settings_v1, tara_scalper_v1, tara_mission_v1,
//       tara_speed_dial, tara_attempted_windows_v1, tara_kill_switch_v1,
//       tara_anti_tilt_v1 → mirrored to tara_state with localStorage_* prefix
//
//   OUT: tara_kalshi_creds_v1 (RSA private key) — stays localStorage-ONLY.
//        Per user decision 2026-05-14: a Supabase compromise must NOT enable
//        unauthorized order placement. Kalshi auth must be re-entered per
//        device. This is the only intentional cross-device friction.
//
// SCHEMA (single table, JSON-per-path, drop-in Firestore replacement)
//   create table tara_state (
//     doc_path    text primary key,           -- e.g. 'memory/taraCallLog'
//     data        jsonb not null,             -- the document body
//     updated_at  timestamptz default now() not null,
//     updated_by  text                        -- optional device fingerprint
//   );
//   alter table tara_state enable row level security;
//   create policy "shared tara read"   on tara_state for select using (true);
//   create policy "shared tara write"  on tara_state for insert with check (true);
//   create policy "shared tara update" on tara_state for update using (true);
//
// AUTH MODEL
//   No sign-in. Single shared global namespace. Anonymous anon-key client.
//   Matches existing Firestore "Shared Tara" pattern. Anyone with the
//   deployment URL has full read/write to the dataset. This is intentional —
//   the user has been operating this way and confirmed they want to keep it.
//
// CONCURRENCY (RMW replacement)
//   Firestore had runTransaction (atomic read-modify-write). Postgres uses
//   upsert with timestamp conflict resolution:
//
//     insert into tara_state (doc_path, data, updated_at)
//     values ($path, $merged_data, now())
//     on conflict (doc_path) do update
//       set data = excluded.data,
//           updated_at = now()
//       where tara_state.updated_at < excluded.updated_at_local;
//
//   The client passes its local 'updated_at' (when it last knew the cloud
//   state) so the SQL only commits if no newer write has happened since.
//   On rejection, client re-reads + re-merges + retries (up to 5x). This
//   matches Firestore's runTransaction semantics.
//
//   For the call log specifically, the merge happens CLIENT-SIDE (same merge
//   function used by existing cloudWriteDebouncedRMW callers). Server just
//   stores the merged blob.
//
// PARALLEL-WRITE PHASE (this is what protects us during migration)
//   During Sessions 2-3, BOTH Firestore AND Supabase get every write. If one
//   fails, the other still has the data. If we screw up Supabase code, we
//   lose nothing — Firestore is still primary. Only after we've verified
//   Supabase has full parity do we flip the primary reader, and only after
//   running stable for a few days do we remove Firestore code.
//
// MIGRATION ORDER (across sessions)
//   Session 1 (CURRENT): spec lock, SQL provided, client helpers built,
//                        parallel-write wired in for state/lifetimePnL only
//                        as proof of life. Firestore remains primary reader.
//   Session 2:           parallel-write extended to taraCallLog + all
//                        learnings. One-time migration script for existing
//                        Firestore data (read all 700+ trades, write to
//                        Supabase). Run migration. Verify counts match.
//   Session 3:           flip primary reader to Supabase. Firestore writes
//                        continue as backup. Sync tab UI reads from Supabase.
//   Session 4:           remove Firestore code entirely. Drop firebase npm
//                        package. Clean up FIREBASE_CONFIG, _fbDb references.
//                        Settings UI cleanup.
//
// HELPER API (drop-in Firestore replacements — preserve all signatures)
//   cloudWrite(path, data)                 — fire-and-forget write
//   cloudRead(path) → Promise<data|null>   — one-shot read
//   cloudWatch(path, callback) → unsub     — subscribe to changes
//   cloudWriteDebouncedRMW(path, getLocalData, mergeFn, delayMs?)  — atomic RMW
//   cloudDelete(path)                      — delete a doc
//
//   Every existing call site continues to work without modification during
//   the parallel-write phase. New Supabase versions live alongside Firestore
//   versions and are invoked together by a wrapper.
//
// SUCCESS CRITERIA
//   1. Sync tab shows non-zero counts from Supabase
//   2. Call log entries from one device appear on another within ~30s
//   3. Lifetime P&L matches between devices
//   4. Force Resync / Save Baseline / Apply Baseline all work as today
//   5. No new console errors from Supabase code
//   6. Firestore quota errors stop (or at minimum, are not user-facing)
//
// ROLLBACK
//   At any point in Sessions 1-3, removing the Supabase wrapper call leaves
//   Firestore fully functional. The Supabase code is purely additive until
//   Session 3's primary-reader flip. Session 4 is the only one-way step.
//
// ═══════════════════════════════════════════════════════════════════════════

// Supabase project credentials (V10.1.0). Both are public-safe — the anon
//   key is JWT-encoded and designed for client bundles. RLS policies control
//   what the anon role can actually do (read/write the tara_state table).
const SUPABASE_URL='https://vhbbkqmyyzddhezdgszm.supabase.co';
const SUPABASE_ANON_KEY='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZoYmJrcW15eXpkZGhlemRnc3ptIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzg3ODMzNjUsImV4cCI6MjA5NDM1OTM2NX0.30zC6hbGEcCNSuOQNRfh81_3B0nwVDuUJeeqUydZCoM';
// Supabase client is initialized lazily below after the helper module loads.
// During the parallel-write phase, _sbClient may be null if init fails — code
// must check before calling. Failed Supabase init is non-fatal (Firestore
// remains primary). Logged once on init.
let _sbClient=null;
let _sbInitAttempted=false;
let _sbInitError=null;

// V10.1.0 — Supabase init. Mirrors the Firestore init pattern at L35. Fail-soft:
//   if the client can't be created, log a warning and leave _sbClient=null. The
//   parallel-write wrapper checks for null before each call so a broken Supabase
//   doesn't break the app.
try{
  _sbInitAttempted=true;
  if(typeof createSupabaseClient==='function'&&SUPABASE_URL&&SUPABASE_ANON_KEY){
    _sbClient=createSupabaseClient(SUPABASE_URL,SUPABASE_ANON_KEY,{
      auth:{
        // No sign-in flow — Shared Tara model. Disable session persistence and
        //   auto-refresh since we're using the anon role only.
        persistSession:false,
        autoRefreshToken:false,
        detectSessionInUrl:false,
      },
      // Realtime opted in but with conservative defaults. We'll wire up the
      //   subscription helpers (cloudSupabaseWatch) but keep them off by default
      //   during Sessions 1-2 to avoid surprises.
      realtime:{params:{eventsPerSecond:2}},
    });
    console.info('[Supabase] init ok — anon role, RLS policies active');
  } else {
    _sbInitError='createSupabaseClient unavailable or credentials missing';
    console.warn('[Supabase] init skipped:',_sbInitError);
  }
} catch(e){
  _sbInitError=e?.message||String(e);
  _sbClient=null;
  console.warn('[Supabase] init failed:',_sbInitError);
}

// V10.1.0 — Supabase helper functions. Match Firestore helper signatures so
//   they can be wired in parallel without touching call sites.
//
// Path convention: doc_path is a slash-separated string like 'memory/taraCallLog'.
//   Stored as-is in the tara_state.doc_path column. No path parsing needed.

// One-shot write: insert or update a single doc. Best-effort, fire-and-forget
//   (no error throws to caller). Used for non-RMW paths.
const cloudSupabaseWrite=async(path,data)=>{
  if(!_sbClient||!path)return false;
  try{
    const {error}=await _sbClient.from('tara_state').upsert({
      doc_path:path,
      data:data,
      updated_at:new Date().toISOString(),
    },{onConflict:'doc_path'});
    if(error){console.warn('[Supabase] write failed',path,error.message);return false;}
    return true;
  }catch(e){
    console.warn('[Supabase] write threw',path,e?.message);
    return false;
  }
};

// One-shot read: fetch a single doc by path. Returns the data payload or null.
//   Matches cloudRead signature.
const cloudSupabaseRead=async(path)=>{
  if(!_sbClient||!path)return null;
  try{
    const {data,error}=await _sbClient.from('tara_state').select('data,updated_at').eq('doc_path',path).maybeSingle();
    if(error){
      // PGRST116 = no rows found, which is "missing doc" (not an error for us)
      if(error.code!=='PGRST116')console.warn('[Supabase] read failed',path,error.message);
      return null;
    }
    if(!data)return null;
    return data.data; // unwrap the jsonb column
  }catch(e){
    console.warn('[Supabase] read threw',path,e?.message);
    return null;
  }
};

// Subscribe to changes on a specific doc. Returns an unsubscribe function.
//   Matches cloudWatch signature: callback receives the new data payload.
//   Uses Supabase Realtime postgres_changes events.
const cloudSupabaseWatch=(path,callback)=>{
  if(!_sbClient||!path||typeof callback!=='function')return ()=>{};
  let _ch=null;
  try{
    // Channel per path so each subscriber has its own. Supabase auto-merges
    //   internally so the cost is low.
    _ch=_sbClient.channel(`tara_state:${path}`)
      .on('postgres_changes',{
        event:'*',
        schema:'public',
        table:'tara_state',
        filter:`doc_path=eq.${path}`,
      },(payload)=>{
        try{
          // payload.new has the row after change; payload.old for deletes
          const _row=payload.new||payload.old;
          callback(_row?.data||null);
        }catch(e){console.warn('[Supabase] watch callback threw',path,e?.message);}
      })
      .subscribe();
  }catch(e){
    console.warn('[Supabase] watch subscribe threw',path,e?.message);
    return ()=>{};
  }
  return ()=>{
    try{if(_ch)_sbClient.removeChannel(_ch);}catch(_){}
  };
};

// Delete a doc by path. Matches cloudDelete signature.
const cloudSupabaseDelete=async(path)=>{
  if(!_sbClient||!path)return false;
  try{
    const {error}=await _sbClient.from('tara_state').delete().eq('doc_path',path);
    if(error){console.warn('[Supabase] delete failed',path,error.message);return false;}
    return true;
  }catch(e){
    console.warn('[Supabase] delete threw',path,e?.message);
    return false;
  }
};

// V10.1.0 — Debounced RMW (read-modify-write). Matches cloudWriteDebouncedRMW.
//   Postgres lacks Firestore's runTransaction primitive, so we implement RMW
//   via optimistic concurrency:
//     1. Read current cloud value + updated_at
//     2. Call mergeFn(cloudData, localData) → merged
//     3. Upsert with a conditional: only commit if cloud.updated_at hasn't
//        changed since our read
//     4. If commit rejected (someone else wrote between our read and write),
//        retry up to 5 times with fresh reads
//
//   Same per-path debounce as the Firestore version (separate timer map).
const _sbWriteQueueRMW=new Map();
const _sbWritePendingRMW=new Map();
const cloudSupabaseWriteDebouncedRMW=(path,getLocalData,mergeFn,delayMs=400)=>{
  if(!_sbClient||!path)return;
  if(_sbWriteQueueRMW.has(path))clearTimeout(_sbWriteQueueRMW.get(path));
  _sbWritePendingRMW.set(path,{getLocalData,mergeFn});
  const tid=setTimeout(async()=>{
    _sbWriteQueueRMW.delete(path);
    _sbWritePendingRMW.delete(path);
    if(!_sbClient)return;
    // Optimistic RMW with retry. 5 attempts matches Firestore default.
    let _attempts=0;
    while(_attempts<5){
      _attempts++;
      try{
        // Read current state
        const {data:_cur,error:_readErr}=await _sbClient.from('tara_state')
          .select('data,updated_at').eq('doc_path',path).maybeSingle();
        if(_readErr&&_readErr.code!=='PGRST116'){
          console.warn('[Supabase] RMW read failed',path,_readErr.message);
          return;
        }
        const _cloudData=_cur?.data||null;
        const _cloudUpdatedAt=_cur?.updated_at||null;
        const _localData=getLocalData();
        const _merged=mergeFn(_cloudData,_localData);
        if(_merged==null)return; // mergeFn signaled "skip write"
        // Conditional upsert: succeed only if row's updated_at hasn't changed.
        //   For a brand-new row (no _cloudUpdatedAt), this is an INSERT and
        //   has no conflict to check. For an existing row, we use the eq()
        //   filter on updated_at to enforce optimistic concurrency.
        if(_cloudUpdatedAt){
          // Update with concurrency check
          const {error:_updateErr,count}=await _sbClient.from('tara_state')
            .update({data:_merged,updated_at:new Date().toISOString()},{count:'exact'})
            .eq('doc_path',path)
            .eq('updated_at',_cloudUpdatedAt);
          if(_updateErr){
            console.warn('[Supabase] RMW update failed',path,_updateErr.message);
            return;
          }
          if(count===0){
            // Conflict — someone else wrote. Retry from the top.
            if(_attempts>=5){console.warn('[Supabase] RMW gave up after 5 attempts',path);return;}
            await new Promise(r=>setTimeout(r,50*_attempts));
            continue;
          }
          return; // success
        } else {
          // No existing row — plain insert. If it conflicts (race with another
          //   first-time inserter), retry from the top.
          const {error:_insertErr}=await _sbClient.from('tara_state')
            .insert({doc_path:path,data:_merged,updated_at:new Date().toISOString()});
          if(_insertErr){
            // 23505 = unique violation = someone else inserted first. Retry.
            if(_insertErr.code==='23505'){
              if(_attempts>=5){console.warn('[Supabase] RMW insert gave up',path);return;}
              await new Promise(r=>setTimeout(r,50*_attempts));
              continue;
            }
            console.warn('[Supabase] RMW insert failed',path,_insertErr.message);
            return;
          }
          return; // success
        }
      } catch(e){
        console.warn('[Supabase] RMW threw',path,e?.message);
        return;
      }
    }
  },delayMs);
  _sbWriteQueueRMW.set(path,tid);
};

// Force-flush all pending Supabase RMW writes (called on tab close).
//   Best-effort, since async network calls may not complete before unload.
const _cloudSupabaseFlushAllRMW=()=>{
  let _flushed=0;
  for(const[path,tid]of _sbWriteQueueRMW.entries()){
    clearTimeout(tid);
    const entry=_sbWritePendingRMW.get(path);
    if(entry){
      try{
        const _localData=entry.getLocalData();
        const _merged=entry.mergeFn(null,_localData);
        if(_merged!=null)cloudSupabaseWrite(path,_merged);
        _flushed++;
      }catch(_){}
    }
  }
  _sbWriteQueueRMW.clear();
  _sbWritePendingRMW.clear();
  return _flushed;
};

// V10.2.0: stubbed. Firestore retired; `doc()` from firebase/firestore is no longer
//   imported. Returns null so any leftover reference fails the standard `if(!ref)` guard
//   that all helpers used to perform. No-op safety net rather than removed-and-crash.
const _fbDoc=(_path)=>null;
// V5.6.1: Cloud sync status — subscribers (React components) get notified on state change.
//   States: 'idle' (no recent activity), 'writing' (debounced or in-flight), 'ok' (last
//   write succeeded), 'error' (last write/read failed). Used for a visible indicator dot.
// V5.6.3: Track active onSnapshot listeners. If listeners > 0, real-time sync is alive
//   and changes from any device propagate within ~1s without refresh. If listeners = 0
//   but Firestore is initialized, something's wrong (rules, network, etc.).
const _cloudSyncListeners=new Set();
// V10.2.0: tracks Supabase health (was Firestore). State terminology unchanged so UI components don't need updating.
let _cloudSyncStatus={state:_sbClient?'idle':'disabled',lastOk:null,lastError:null,writes:0,reads:0,listeners:0};
const _setCloudStatus=(patch)=>{_cloudSyncStatus={..._cloudSyncStatus,...patch};_cloudSyncListeners.forEach(l=>l(_cloudSyncStatus));};
const subscribeCloudStatus=(fn)=>{_cloudSyncListeners.add(fn);fn(_cloudSyncStatus);return()=>_cloudSyncListeners.delete(fn);};
// V8.8.7: Active-write counter. Each cloudWrite / cloudWriteDebouncedRMW transaction
//   increments on start, decrements on completion (success or failure). State stays
//   'writing' as long as count>0, so concurrent writes from multiple sync paths
//   don't oscillate writing→ok→writing→ok the way they did when each path toggled
//   the global state independently. The pill applies an additional 750ms render
//   hysteresis on top of this so brief writes never flicker.
let _activeWrites=0;
const _incActiveWrites=()=>{
  _activeWrites++;
  if(_activeWrites===1)_setCloudStatus({state:'writing'});
};
const _decActiveWrites=(success)=>{
  _activeWrites=Math.max(0,_activeWrites-1);
  if(_activeWrites===0&&success){
    _setCloudStatus({state:'ok',lastOk:Date.now(),writes:_cloudSyncStatus.writes+1});
  }
  // If !success, the catch handler already set state:'error' — leave it.
  // If count still >0, leave state at 'writing' — another write is in flight.
};

// ── V8.3: CROSS-TAB BROADCAST CHANNEL ────────────────────────────────────────
// Instant cross-tab messaging within the same browser. Eliminates the ~1s wait for
// Firestore round-trip when one tab adds an entry — other tabs see it immediately.
// Backed up by Firestore + RMW writes for cross-device + cross-browser sync.
const _crossTab=(typeof BroadcastChannel!=='undefined')?(()=>{try{return new BroadcastChannel('tara-cross-tab-v1');}catch(_){return null;}})():null;
// V9.2.1: Cross-asset price channel. Separate from the call-log cross-tab channel.
//   Each tab broadcasts its current asset + price every 5s. Other-asset tabs read it
//   to detect correlation (e.g., BTC dumping → penalize ETH UP calls).

// V9.2.1 → V9.8.14: Sound alerts via Web Audio API. Minimal beep function — no audio
//   files needed. Called by spike alerts + trade coach urgent cards. User can mute via
//   localStorage.
// V9.8.14: Singleton AudioContext + audio-thread scheduling. Old V9.2.1 implementation
//   created a new AudioContext on every beep call — browsers cap context creation
//   (~6 in Chrome, fewer on iOS) so after enough beeps new contexts came back
//   suspended-and-stuck and no further sound played. Multi-tone beeps used setTimeout
//   for sequencing, which is throttled to >=1s when a tab is backgrounded — sequenced
//   beeps fired as a single muffled tone or not at all.
//   Now: one shared module-level context, lazily created, resumed on first user
//   gesture and on every visibilitychange→visible. Multi-tone sequences scheduled via
//   internal AudioContext timing (oscillator.start(ctx.currentTime + delay)) which
//   the audio thread honors regardless of JS event-loop throttling. Reliable across
//   visible-but-unfocused tabs. Truly backgrounded tabs (different tab focused) still
//   suspended — that's a browser-level constraint, fixable only via Notifications API.
let _sharedAudioCtx=null;
// V9.9.6: HTMLAudioElement fallback — preloaded WAV-encoded short tones. Used when
//   AudioContext is unavailable OR stuck suspended (Brave Shields, mobile background).
//   Generated as base64 WAV at module load. Three flavors: short beep, urgent double,
//   spike-against descending. Same pitch family as the AudioContext oscillators so the
//   user perceives a consistent sound across fallback transitions.
let _fallbackPool=null;
const _genWavBase64=(freq,durMs,vol)=>{
  // 8kHz mono 16-bit PCM single-tone — kept tiny so all variants live in memory.
  const sr=8000,n=Math.floor(sr*durMs/1000),amp=Math.floor(vol*32767);
  const buf=new ArrayBuffer(44+n*2),v=new DataView(buf);
  const w=(o,s)=>{for(let i=0;i<s.length;i++)v.setUint8(o+i,s.charCodeAt(i));};
  w(0,'RIFF');v.setUint32(4,36+n*2,true);w(8,'WAVE');w(12,'fmt ');
  v.setUint32(16,16,true);v.setUint16(20,1,true);v.setUint16(22,1,true);
  v.setUint32(24,sr,true);v.setUint32(28,sr*2,true);v.setUint16(32,2,true);v.setUint16(34,16,true);
  w(36,'data');v.setUint32(40,n*2,true);
  for(let i=0;i<n;i++){
    // 12ms fade-in/out so the start/end isn't a click.
    const fade=Math.min(1,i/(sr*0.012),(n-i)/(sr*0.012));
    v.setInt16(44+i*2,Math.sin(2*Math.PI*freq*i/sr)*amp*fade,true);
  }
  let s='';const u=new Uint8Array(buf);
  for(let i=0;i<u.length;i++)s+=String.fromCharCode(u[i]);
  return'data:audio/wav;base64,'+btoa(s);
};
const _getFallback=()=>{
  if(_fallbackPool)return _fallbackPool;
  if(typeof Audio==='undefined')return null;
  try{
    _fallbackPool={
      beep:new Audio(_genWavBase64(880,150,0.18)),
      urgent:new Audio(_genWavBase64(1100,280,0.22)),
      spike:new Audio(_genWavBase64(700,320,0.20)),
      win:new Audio(_genWavBase64(1000,300,0.18)),
    };
    Object.values(_fallbackPool).forEach(a=>{a.preload='auto';});
    return _fallbackPool;
  }catch(_){return null;}
};
const _getAudioCtx=()=>{
  if(typeof window==='undefined')return null;
  if(_sharedAudioCtx)return _sharedAudioCtx;
  try{
    const Ctx=window.AudioContext||window.webkitAudioContext;
    if(!Ctx)return null;
    _sharedAudioCtx=new Ctx();
    return _sharedAudioCtx;
  }catch(_){return null;}
};
// V9.9.6: aggressive resume — try to wake the context, with promise-tracking so we
//   don't fire multiple concurrent resume() calls (which can confuse some browser
//   audio implementations). Returns true if context is or becomes running.
let _resumePromise=null;
const _resumeCtx=(ctx)=>{
  if(!ctx)return Promise.resolve(false);
  if(ctx.state==='running')return Promise.resolve(true);
  if(_resumePromise)return _resumePromise;
  _resumePromise=ctx.resume().then(()=>{_resumePromise=null;return ctx.state==='running';}).catch(()=>{_resumePromise=null;return false;});
  return _resumePromise;
};
if(typeof window!=='undefined'){
  // V9.9.6: bootstrap on EVERY user gesture (not just first), and never remove the
  //   listener. Browsers throttle/suspend AudioContext on tab inactive, system sleep,
  //   focus loss, etc. — re-resuming on every click is cheap and bullet-proof. Also
  //   prefetch the fallback pool on first interaction so HTMLAudioElement is ready.
  const _wakeOnGesture=()=>{
    const c=_getAudioCtx();
    if(c&&c.state!=='running')_resumeCtx(c);
    _getFallback(); // preload fallback audio elements
  };
  try{
    // Capture-phase, passive listeners — every click/tap/key wakes audio. No removal.
    window.addEventListener('pointerdown',_wakeOnGesture,{capture:true,passive:true});
    window.addEventListener('keydown',_wakeOnGesture,{capture:true,passive:true});
    window.addEventListener('touchstart',_wakeOnGesture,{capture:true,passive:true});
    // Tab visibility change — resume on return from background.
    document.addEventListener('visibilitychange',()=>{
      if(document.visibilityState==='visible'){
        const c=_sharedAudioCtx;
        if(c&&c.state!=='running')_resumeCtx(c);
      }
    });
    // Window focus — additional safety, fires on Cmd-Tab back.
    window.addEventListener('focus',()=>{
      const c=_sharedAudioCtx;
      if(c&&c.state!=='running')_resumeCtx(c);
    });
    // Page show (back/forward cache restore) — Safari+iOS path.
    window.addEventListener('pageshow',()=>{
      const c=_sharedAudioCtx;
      if(c&&c.state!=='running')_resumeCtx(c);
    });
  }catch(_){}
}
// Schedule a single beep at ctx.currentTime + offsetSec. Audio-thread timing — survives
//   JS throttling when tab is unfocused (as long as not fully backgrounded).
const _scheduleBeep=(ctx,freq,durationMs,vol,offsetSec)=>{
  try{
    const osc=ctx.createOscillator();
    const gain=ctx.createGain();
    osc.connect(gain);gain.connect(ctx.destination);
    osc.frequency.value=freq;osc.type='sine';
    const t0=ctx.currentTime+(offsetSec||0);
    const dur=durationMs/1000;
    gain.gain.setValueAtTime(0.0001,t0);
    gain.gain.exponentialRampToValueAtTime(Math.max(0.0001,vol),t0+0.005);
    gain.gain.exponentialRampToValueAtTime(0.0001,t0+dur);
    osc.start(t0);
    osc.stop(t0+dur+0.05);
  }catch(_){}
};
// V9.9.6: unified play-or-fallback. Tries AudioContext first (preferred — precise
//   timing + multi-tone scheduling). If ctx is unavailable or stuck suspended after
//   a resume attempt, falls back to HTMLAudioElement with a cloned node (so rapid
//   re-plays work). Logs nothing on the happy path — silent unless something fails.
const _playWithFallback=(scheduleFn,fallbackKey)=>{
  try{
    if(typeof window==='undefined')return;
    const ctx=_getAudioCtx();
    if(ctx){
      // Try resume if suspended (synchronous check, async resume — fire scheduling
      //   anyway since browsers commonly suspend mid-tick and the schedule queue is
      //   honored once context wakes back up). If state is 'closed' we fall through.
      if(ctx.state==='running'){scheduleFn(ctx);return;}
      if(ctx.state==='suspended'){
        _resumeCtx(ctx).then(ok=>{
          if(ok){scheduleFn(ctx);}
          else{
            // Fallback: AudioContext refused to resume (page is fully backgrounded
            //   or browser policy blocked it). Try HTMLAudioElement.
            const pool=_getFallback();
            const a=pool&&pool[fallbackKey];
            if(a){try{const c=a.cloneNode(true);c.volume=0.6;c.play().catch(()=>{});}catch(_){}}
          }
        });
        return;
      }
    }
    // No context at all — fallback path.
    const pool=_getFallback();
    const a=pool&&pool[fallbackKey];
    if(a){try{const c=a.cloneNode(true);c.volume=0.6;c.play().catch(()=>{});}catch(_){}}
  }catch(_){}
};
const _taraUrgentBeep=()=>{
  _playWithFallback((ctx)=>{
    _scheduleBeep(ctx,1000,120,0.2,0);
    _scheduleBeep(ctx,1200,120,0.2,0.180);
  },'urgent');
};
const _taraSpikeBeep=()=>{
  _playWithFallback((ctx)=>{
    _scheduleBeep(ctx,1200,100,0.25,0);
    _scheduleBeep(ctx,900,100,0.2,0.140);
    _scheduleBeep(ctx,600,150,0.15,0.300);
  },'spike');
};
const _taraWinBeep=()=>{
  _playWithFallback((ctx)=>{
    _scheduleBeep(ctx,600,100,0.15,0);
    _scheduleBeep(ctx,900,100,0.15,0.140);
    _scheduleBeep(ctx,1200,150,0.2,0.300);
  },'win');
};
const _crossAssetChannel=(typeof BroadcastChannel!=='undefined')?(()=>{try{return new BroadcastChannel('tara-cross-asset-v1');}catch(_){return null;}})():null;
const broadcastToOtherTabs=(type,payload)=>{
  if(!_crossTab)return;
  try{_crossTab.postMessage({type,payload,t:Date.now()});}catch(_){}
};
const subscribeToOtherTabs=(handler)=>{
  if(!_crossTab)return()=>{};
  const fn=(event)=>{try{handler(event.data);}catch(_){}};
  _crossTab.addEventListener('message',fn);
  return()=>{try{_crossTab.removeEventListener('message',fn);}catch(_){}};
};
// V8.3: Tab heartbeat — each tab broadcasts a heartbeat every 5s so peers can detect
//   how many tabs are active. Stored in module-level Map keyed by tabId.
const _tabId=Math.random().toString(36).slice(2,10)+'-'+Date.now().toString(36);
const _peerTabs=new Map(); // tabId → {lastSeen, currentAsset}
let _peerListeners=new Set();
const _notifyPeerListeners=()=>{_peerListeners.forEach(fn=>{try{fn(Array.from(_peerTabs.entries()));}catch(_){}});};
if(_crossTab){
  _crossTab.addEventListener('message',(event)=>{
    const d=event.data;
    if(!d||d.type!=='heartbeat')return;
    const{tabId,currentAsset}=d.payload||{};
    if(!tabId||tabId===_tabId)return;
    _peerTabs.set(tabId,{lastSeen:Date.now(),currentAsset});
    _notifyPeerListeners();
  });
  // GC peers that haven't been heard from in 15s
  setInterval(()=>{
    const now=Date.now();
    let changed=false;
    for(const[id,info]of _peerTabs.entries()){
      if(now-info.lastSeen>15000){_peerTabs.delete(id);changed=true;}
    }
    if(changed)_notifyPeerListeners();
  },5000);
}
const subscribeToPeerTabs=(fn)=>{_peerListeners.add(fn);fn(Array.from(_peerTabs.entries()));return()=>_peerListeners.delete(fn);};
const getCurrentTabId=()=>_tabId;

// V10.2.0: cloudRead now reads from Supabase. Signature unchanged so call sites work as-is.
const cloudRead=async(path)=>{
  if(!path)return null;
  try{
    const data=await cloudSupabaseRead(path);
    _setCloudStatus({state:'ok',lastOk:Date.now(),reads:_cloudSyncStatus.reads+1});
    return data;
  }catch(e){
    console.warn('[Cloud read failed]',path,e?.message);
    _setCloudStatus({state:'error',lastError:{path,message:e?.message,at:Date.now()}});
    return null;
  }
};
// V10.2.0: cloudWrite now writes to Supabase only. Was dual-write (Firestore + Supabase)
//   in Session 2. Firestore retired. Call sites still see the same (path, data) signature.
const cloudWrite=async(path,data)=>{
  if(!path)return false;
  _incActiveWrites();
  let _ok=false;
  try{
    _ok=await cloudSupabaseWrite(path,data);
    if(!_ok){
      _setCloudStatus({state:'error',lastError:{path,message:'Supabase write returned false',at:Date.now()}});
    }
    return _ok;
  }catch(e){
    console.warn('[Cloud write failed]',path,e?.message);
    _setCloudStatus({state:'error',lastError:{path,message:e?.message,at:Date.now()}});
    return false;
  }finally{
    _decActiveWrites(_ok);
  }
};
// V10.2.0: cloudDelete now removes from Supabase. Signature unchanged.
const cloudDelete=async(path)=>{
  if(!path)return false;
  try{
    const ok=await cloudSupabaseDelete(path);
    if(ok)_setCloudStatus({state:'ok',lastOk:Date.now(),writes:_cloudSyncStatus.writes+1});
    return ok;
  }catch(e){
    console.warn('[Cloud delete failed]',path,e?.message);
    _setCloudStatus({state:'error',lastError:{path,message:e?.message,at:Date.now()}});
    return false;
  }
};


// ── V9.10.7: AUDIT LOG for silent log-write failures ────────────────────────
// Why: V9.10.6 surfaced an incident where Tara emitted a Discord embed for a
//   DOWN no-go-data lock at 1:45 AM but no matching entry appeared in taraCallLog.
//   The _logSnapshotEntry try/catch swallows throws to console-only, and the dedup
//   checks in both _logSnapshotEntry and the directional commit path silently
//   return prev unchanged when a keyed entry already exists. We had no evidence
//   of which silent path fired.
// What: this module captures every silent skip + every caught throw to a ring
//   buffer, persists last N events to localStorage, and replicates to a cloud
//   doc memory/log_audit. Going forward, anytime "Tara called but didn't log"
//   recurs, we can read the audit doc and see exactly which path swallowed the
//   write — without having had DevTools open at the moment.
// Storage: ring buffer of 200 events (~50KB max). Cloud writes debounced 2s.
const _LOG_AUDIT_LS_KEY='taraLogAudit_v1';
const _LOG_AUDIT_CAP=200;
let _logAuditBuffer=null;
const _loadAuditBuffer=()=>{
  if(_logAuditBuffer)return _logAuditBuffer;
  try{
    const _raw=typeof localStorage!=='undefined'?localStorage.getItem(_LOG_AUDIT_LS_KEY):null;
    _logAuditBuffer=_raw?JSON.parse(_raw):[];
    if(!Array.isArray(_logAuditBuffer))_logAuditBuffer=[];
  }catch(_){_logAuditBuffer=[];}
  return _logAuditBuffer;
};
const _persistAuditBuffer=()=>{
  try{
    if(typeof localStorage!=='undefined'){
      localStorage.setItem(_LOG_AUDIT_LS_KEY,JSON.stringify((_logAuditBuffer||[]).slice(-_LOG_AUDIT_CAP)));
    }
  }catch(_){}
};
let _auditCloudTimer=null;
const _scheduleAuditCloudWrite=()=>{
  if(_auditCloudTimer)clearTimeout(_auditCloudTimer);
  _auditCloudTimer=setTimeout(()=>{
    try{
      const _buf=(_logAuditBuffer||[]).slice(-_LOG_AUDIT_CAP);
      cloudWrite('memory/log_audit',{events:_buf,updatedAt:Date.now()}).catch(()=>{});
    }catch(_){}
  },2000);
};
const _auditLogEvent=(kind,details)=>{
  try{
    const _buf=_loadAuditBuffer();
    _buf.push({kind,at:Date.now(),ts:new Date().toISOString(),...details});
    while(_buf.length>_LOG_AUDIT_CAP)_buf.shift();
    _persistAuditBuffer();
    _scheduleAuditCloudWrite();
    try{console.warn('[V9.10.7 log_audit]',kind,details);}catch(_){}
  }catch(_){}
};
// DevTools convenience: window._tara_audit() returns the in-memory buffer.
try{if(typeof window!=='undefined'){window._tara_audit=()=>_loadAuditBuffer();}}catch(_){}
// ─────────────────────────────────────────────────────────────────────────────

// V5.6.2: Real-time listener — fires once with current cloud value, then again on every
//   change from any connected client. This is what makes cross-device sync actually work:
//   Device A writes, Device B's listener fires within ~1s, B's UI updates without refresh.
//   Returns an unsubscribe function the caller stores in a useEffect cleanup.
// V5.6.3: Tracks active listener count in sync status — so the badge can show whether
//   real-time sync is actually established vs. just one-shot reads happening.
// V10.2.0: cloudWatch now uses Supabase Realtime (postgres_changes). Mirrors the prior
//   Firestore onSnapshot semantics: an initial read fires the callback once with current
//   data, then subsequent row changes stream in. Callback signature preserved
//   (data, status) — status is one of 'ok'|'error'|'disabled'.
const cloudWatch=(path,callback)=>{
  if(!path||typeof callback!=='function'){try{callback&&callback(null,'disabled');}catch(_){}return()=>{};}
  _setCloudStatus({listeners:_cloudSyncStatus.listeners+1});
  // Initial read so the callback fires with current state (matches old onSnapshot behavior).
  cloudSupabaseRead(path).then(d=>{
    _setCloudStatus({state:'ok',lastOk:Date.now(),reads:_cloudSyncStatus.reads+1});
    try{callback(d,'ok');}catch(_){}
  }).catch(err=>{
    console.warn('[Cloud watch initial-read failed]',path,err?.message);
    _setCloudStatus({state:'error',lastError:{path,message:err?.message,at:Date.now()}});
    try{callback(null,'error');}catch(_){}
  });
  // Subscribe to subsequent changes.
  const unsub=cloudSupabaseWatch(path,(d)=>{
    _setCloudStatus({state:'ok',lastOk:Date.now(),reads:_cloudSyncStatus.reads+1});
    try{callback(d,'ok');}catch(_){}
  });
  return()=>{
    _setCloudStatus({listeners:Math.max(0,_cloudSyncStatus.listeners-1)});
    try{unsub();}catch(_){}
  };
};
// Coalesces rapid updates per-path into a single Firestore write (saves quota + bandwidth).
const _writeQueue=new Map();
// V8.1: Track latest pending data per path so we can synchronously flush on tab close.
//   Map of path → most recent data, separate from the timeout map.
const _writePending=new Map();
const cloudWriteDebounced=(path,data,delayMs=300)=>{
  if(_writeQueue.has(path))clearTimeout(_writeQueue.get(path));
  _writePending.set(path,data);
  const tid=setTimeout(()=>{
    cloudWrite(path,data);
    _writeQueue.delete(path);
    _writePending.delete(path);
  },delayMs);
  _writeQueue.set(path,tid);
};
// V8.1: Synchronously fire all pending debounced writes. Called on pagehide/beforeunload
//   so trades made just before tab close don't get lost in the 300ms debounce window.
//   Returns the count of writes flushed.
const cloudFlushAll=()=>{
  let flushed=0;
  for(const[path,tid]of _writeQueue.entries()){
    clearTimeout(tid);
    const data=_writePending.get(path);
    if(data!=null){
      // Fire-and-forget — no await. Modern browsers respect the in-flight fetch
      //   on pagehide for a brief grace period. Firestore writes use fetch internally.
      try{cloudWrite(path,data);flushed++;}catch(_){}
    }
  }
  _writeQueue.clear();
  _writePending.clear();
  return flushed;
};
// V8.1: Wire flush to tab visibility change events. Browsers fire pagehide reliably
//   on real tab close + navigation; visibilitychange covers tab switch/minimize.
// V8.3: Now also drains RMW queue (best-effort; local-only write if cloud read can't complete).
//   The actual flush function combining both is defined below the RMW helpers.

// ── V8.3: READ-MODIFY-WRITE DEBOUNCED HELPER ────────────────────────────────
// Solves the multi-tab last-write-wins clobbering problem. When timer fires:
//   1. Open Firestore transaction — atomic read+write with auto-retry on conflict
//   2. Inside tx: read current cloud state, call mergeFn(cloudData, currentLocalData),
//      tx.set() the merged result. If another tab wrote between our read and write,
//      Firestore aborts our tx and retries our handler — guaranteeing serialization.
// getLocalData is a function (not a value) so we get the freshest local state when
// the timer fires, even if state changed during the debounce window.
// mergeFn returns null to skip the write entirely (e.g., no changes after merge).
// V10.2.0: now Supabase-only. Was dual-write (Firestore transaction + Supabase upsert)
//   during Session 2. Firestore retired. This helper is a thin wrapper over
//   cloudSupabaseWriteDebouncedRMW which implements optimistic-concurrency RMW
//   (read → merge → conditional update keyed on updated_at). The `_writeQueueRMW`
//   / `_writePendingRMW` Maps remain referenced by `_cloudFlushAllRMW` for the
//   tab-close grace flush — kept in sync below for that use case only.
const _writeQueueRMW=new Map();
const _writePendingRMW=new Map();
const cloudWriteDebouncedRMW=(path,getLocalData,mergeFn,delayMs=400)=>{
  // Mirror into the queue maps so the tab-close flush has visibility.
  if(_writeQueueRMW.has(path))clearTimeout(_writeQueueRMW.get(path));
  _writePendingRMW.set(path,{getLocalData,mergeFn});
  const tid=setTimeout(()=>{
    _writeQueueRMW.delete(path);
    _writePendingRMW.delete(path);
  },delayMs+50);
  _writeQueueRMW.set(path,tid);
  // Actual write goes through the Supabase RMW helper.
  try{cloudSupabaseWriteDebouncedRMW(path,getLocalData,mergeFn,delayMs);}catch(_){}
};
// V8.3: Force-flush all RMW writes synchronously on tab close. Cloud reads can't
//   complete in pagehide grace window, so we write local data without merge — better
//   than losing the write entirely. cloudWatch on other tabs will re-merge.
// V10.2.0: tab-close grace flush. Was a Firestore-only flush that wrote local data
//   without merge. Now delegates to the Supabase-side flush which performs the same
//   role for Supabase pending RMW writes. The Maps maintained above are also cleared.
const _cloudFlushAllRMW=()=>{
  let cleared=0;
  for(const[,tid]of _writeQueueRMW.entries()){clearTimeout(tid);cleared++;}
  _writeQueueRMW.clear();
  _writePendingRMW.clear();
  try{cleared+=_cloudSupabaseFlushAllRMW();}catch(_){}
  return cleared;
};
// Combined flush — called on tab close
// V10.1.0: cloudFlushAllCombined now also drains pending Supabase RMW writes.
//   During the parallel-write phase, this fires both Firestore and Supabase
//   pending writes on tab close. Once Session 4 removes Firestore, this will
//   simplify back to just _cloudSupabaseFlushAllRMW.
// V10.2.0: simplified — _cloudFlushAllRMW now internally drains the Supabase RMW queue,
//   so the explicit _cloudSupabaseFlushAllRMW call is no longer needed here (was needed
//   during Session 2's dual-write phase).
const cloudFlushAllCombined=()=>cloudFlushAll()+_cloudFlushAllRMW();
if(typeof window!=='undefined'){
  const _onLeave=()=>{try{cloudFlushAllCombined();}catch(_){}};
  window.addEventListener('pagehide',_onLeave);
  window.addEventListener('beforeunload',_onLeave);
  window.addEventListener('visibilitychange',()=>{
    if(document.visibilityState==='hidden')_onLeave();
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// V10.2.0 — PHASE 4 LATEST-DECISION PUB/SUB (cross-component bridge)
// ═══════════════════════════════════════════════════════════════════════════
// The Phase 4 evaluation runs inside TaraApp's auto-exec entry effect. The lock
//   UI badge that needs to display the decision lives in a different component
//   (ScalperAdvisorPanel) that doesn't share refs with TaraApp.
//
// Solution: small module-level pub/sub. TaraApp's Phase 4 effect calls
//   _setPhase4Decision(d) after each evaluation. Any component can subscribe via
//   the _usePhase4Decision() hook to receive the latest value reactively.
//
// Decision shape: { decision, score, reason, mode, ts } — same shape as
//   _phase4DecisionRef.current. Subscribers re-render on each new decision.
let _phase4LatestDecision=null;
const _phase4Subscribers=new Set();
const _setPhase4Decision=(d)=>{
  _phase4LatestDecision=d;
  _phase4Subscribers.forEach(fn=>{try{fn(d);}catch(_){}});
};
const _usePhase4Decision=()=>{
  const[d,setD]=React.useState(_phase4LatestDecision);
  React.useEffect(()=>{
    _phase4Subscribers.add(setD);
    return ()=>{_phase4Subscribers.delete(setD);};
  },[]);
  return d;
};

// V10.2.0 — Phase 4 status badge. Subscribes to _phase4LatestDecision via the
//   pub/sub above. Renders nothing when mode is 'off' or no decision exists yet.
//   Used by _renderPredictorHeader to surface what Phase 4 is doing right now,
//   without affecting any trading logic. Color coded: fire-now=emerald,
//   wait=gold, abort=rose, error=gray.
const _Phase4Badge=({mode})=>{
  const d=_usePhase4Decision();
  if(mode==='off'||!mode)return null;
  if(!d||!d.decision)return React.createElement('div',{
    className:'text-[9px] tracking-wider mb-2 px-2 py-0.5 rounded text-center',
    style:{background:'rgba(232,233,228,0.04)',color:'rgba(232,233,228,0.35)'},
    title:`Phase 4 is in '${mode}' mode but no decision yet — waiting for next lock.`,
  },`phase 4 · ${mode} · waiting`);
  const _palette={
    'fire-now':{bg:'rgba(110,231,183,0.10)',fg:'rgb(110,231,183)',border:'rgba(110,231,183,0.25)'},
    'wait':    {bg:'rgba(229,200,112,0.10)',fg:'#E5C870',         border:'rgba(229,200,112,0.25)'},
    'abort':   {bg:'rgba(244,114,128,0.10)',fg:'rgb(244,114,128)',border:'rgba(244,114,128,0.25)'},
    'error':   {bg:'rgba(232,233,228,0.05)',fg:'rgba(232,233,228,0.40)',border:'rgba(232,233,228,0.12)'},
  };
  const c=_palette[d.decision]||_palette.error;
  const _ageSec=d.ts?Math.max(0,Math.floor((Date.now()-d.ts)/1000)):null;
  const _ageLabel=_ageSec==null?'':(_ageSec<60?`${_ageSec}s ago`:`${Math.floor(_ageSec/60)}m ago`);
  return React.createElement('div',{
    className:'text-[9px] tracking-wider mb-2 px-2 py-0.5 rounded text-center flex items-center justify-center gap-1.5',
    style:{background:c.bg,color:c.fg,border:`1px solid ${c.border}`},
    title:`Phase 4 (${mode}) · decision: ${d.decision} · score: ${d.score!=null?d.score:'n/a'}\nTop reasons: ${d.reason||'n/a'}\n${_ageLabel}`,
  },[
    React.createElement('span',{key:'mode',style:{opacity:0.55}},`phase 4 · ${mode} ·`),
    React.createElement('span',{key:'dec',className:'font-bold uppercase'},d.decision),
    d.score!=null&&React.createElement('span',{key:'score',style:{opacity:0.55}},`(${d.score>=0?'+':''}${d.score})`),
  ]);
};

// ═══════════════════════════════════════════════════════════════════════════
// V10.2.0 — PHASE 4 SHADOW DATA ANALYZER (DevTools console hook)
// ═══════════════════════════════════════════════════════════════════════════
// Reads taraCallLog from localStorage, groups by tradeTimingDecision, computes
//   per-group WR + sample stats + top reasons.
//
// Run in DevTools console:
//
//   window.__taraPhase4Stats()
//
// Returns a summary array and prints a console.table. Also checks the graduation
//   gate for advisory promotion (≥50 resolved samples per decision class, with
//   Phase 4 'abort' WR ≥10pt below 'fire-now' WR).
//
// IMPORTANT: only counts entries where Phase 4 was running (mode≠off and a
//   decision was logged). Pre-V10.0.0 trades have no Phase 4 data and show up
//   as 'no-decision'. Expect this bucket to be large early on; ignore it.
if(typeof window!=='undefined'){
  window.__taraPhase4Stats=()=>{
    try{
      const raw=localStorage.getItem('taraCallLog_v1');
      if(!raw){console.warn('[Phase4Stats] no call log in localStorage');return null;}
      const log=JSON.parse(raw);
      if(!Array.isArray(log)){console.warn('[Phase4Stats] call log malformed');return null;}
      const groups={'fire-now':[],'wait':[],'abort':[],'error':[],'no-decision':[]};
      log.forEach(e=>{
        if(!e)return;
        const d=e.tradeTimingDecision;
        const key=(d&&groups[d]!==undefined)?d:'no-decision';
        groups[key].push(e);
      });
      const summary=Object.entries(groups).map(([decision,entries])=>{
        const resolved=entries.filter(e=>e.result==='W'||e.result==='L');
        const wins=resolved.filter(e=>e.result==='W').length;
        const losses=resolved.filter(e=>e.result==='L').length;
        const wrNum=resolved.length>0?(wins/resolved.length*100):null;
        const scores=entries.map(e=>Number(e.tradeTimingScore)).filter(n=>Number.isFinite(n));
        const avgScore=scores.length>0?(scores.reduce((a,b)=>a+b,0)/scores.length):null;
        const reasons=entries.map(e=>e.tradeTimingReason).filter(r=>r);
        const reasonCounts={};
        reasons.forEach(r=>{reasonCounts[r]=(reasonCounts[r]||0)+1;});
        const topReasons=Object.entries(reasonCounts).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([r,c])=>`${r}(${c})`).join(' | ');
        return{
          decision,
          count:entries.length,
          resolved:resolved.length,
          wins,
          losses,
          winRate:wrNum!=null?wrNum.toFixed(1)+'%':'n/a',
          avgScore:avgScore!=null?avgScore.toFixed(1):'n/a',
          topReasons:topReasons||'n/a',
        };
      }).filter(r=>r.count>0);
      console.info('━━━ Phase 4 Shadow Stats ━━━');
      try{console.table(summary);}catch(_){console.info(summary);}
      // Graduation gate check
      const fireGate=summary.find(s=>s.decision==='fire-now');
      const abortGate=summary.find(s=>s.decision==='abort');
      const GATE_N=50;
      if(fireGate&&abortGate&&fireGate.resolved>=GATE_N&&abortGate.resolved>=GATE_N){
        const fireWR=parseFloat(fireGate.winRate);
        const abortWR=parseFloat(abortGate.winRate);
        const delta=fireWR-abortWR;
        console.info(`Graduation gate: fire-now WR=${fireWR.toFixed(1)}%, abort WR=${abortWR.toFixed(1)}%, delta=${delta.toFixed(1)}pt`);
        if(delta>=10){console.info('✓ Phase 4 has signal — ready for ADVISORY promotion');}
        else{console.warn(`Phase 4 abort decisions only ${delta.toFixed(1)}pt below fire-now. Needs ≥10pt gap or tuning.`);}
      }else{
        console.info(`Graduation gate: need ≥${GATE_N} resolved per decision. Current: fire-now=${fireGate?fireGate.resolved:0}, abort=${abortGate?abortGate.resolved:0}.`);
      }
      return summary;
    }catch(e){console.error('[Phase4Stats] failed:',e&&e.message);return null;}
  };
  try{console.info('[Phase4Stats] hook ready — run window.__taraPhase4Stats() in console');}catch(_){}
}

// ═══════════════════════════════════════════════════════════════════════════
// V10.2.x — TARA AUDIT STATS (DevTools console hook)
// ═══════════════════════════════════════════════════════════════════════════
// Re-runs the May 14 audit on demand. Reads taraCallLog from localStorage,
//   computes WR breakdowns across multiple dimensions, and compares each to
//   the May 14 baselines (642-trade audit) so drift is visible.
//
// Run from DevTools console:
//
//   window.__taraAuditStats()                       → everything, all trades
//   window.__taraAuditStats({autoExecOnly:true})    → auto-exec subset only
//   window.__taraAuditStats({asset:'BTC'})          → BTC only
//   window.__taraAuditStats({asset:'ETH',autoExecOnly:true,minN:5})
//
// Output: console.table blocks per dimension — tier, regime, edge bucket,
//   session, window type, asset, direction, auto/manual split, time-cap-commit
//   sub-bands (the V9.19.26 90-119s finding), and v1 vs v2 score-bucket
//   monotonicity comparison (does qScoreV2 predict better than qScore?).
//
// Each row shows n, wins, losses, WR — plus baseline + delta where a May 14
//   number exists. Use to decide which knobs need re-tuning and which clusters
//   are bleeding vs holding their baseline.
if(typeof window!=='undefined'){
  // May 14 audit baselines (642 trades). Empty entries = no baseline captured.
  const _AUDIT_BASELINES={
    tier:{
      'time-cap-commit':62.4,
      'timer-commit':62.4,
      'normal':78.5,
      'early':65.7,
    },
    edge:{
      'edge ≤ -10pt':80.0,
      'edge 0-10pt':70.6,
      'edge 10-20pt':65.1,
      'edge 20-30pt':60.2,
      'edge 30+pt':65.2,
    },
    tcBand:{
      '90-119s':54.6,
    },
  };
  window.__taraAuditStats=(opts={})=>{
    try{
      const raw=localStorage.getItem('taraCallLog_v1');
      if(!raw){console.warn('[AuditStats] no call log in localStorage');return null;}
      const log=JSON.parse(raw);
      if(!Array.isArray(log)){console.warn('[AuditStats] call log malformed');return null;}
      // Filters
      const _asset=opts.asset||opts.assetFilter||'all';
      const _autoOnly=opts.autoExecOnly===true;
      const _minN=Number.isFinite(opts.minN)?opts.minN:3;
      let filtered=log;
      if(_asset!=='all')filtered=filtered.filter(e=>(e?.asset||'BTC')===_asset);
      if(_autoOnly)filtered=filtered.filter(e=>e?.autoExec===true);
      const resolved=filtered.filter(e=>e?.result==='WIN'||e?.result==='LOSS');
      const _wrPct=(w,n)=>n>0?(w/n*100).toFixed(1)+'%':'n/a';
      const _wrNum=(w,n)=>n>0?(w/n*100):null;
      const _delta=(curWR,baseWR)=>{
        if(curWR==null||baseWR==null)return '—';
        const d=curWR-baseWR;
        return (d>=0?'+':'')+d.toFixed(1)+'pt';
      };
      // Generic grouping helper.
      const _groupBy=(entries,keyFn,baselineMap)=>{
        const groups={};
        entries.forEach(e=>{
          const k=keyFn(e);
          if(k==null||k===undefined||k==='')return;
          if(!groups[k])groups[k]={n:0,w:0,l:0};
          groups[k].n++;
          if(e.result==='WIN')groups[k].w++;
          else if(e.result==='LOSS')groups[k].l++;
        });
        return Object.entries(groups)
          .filter(([,v])=>v.n>=_minN)
          .map(([k,v])=>{
            const wr=_wrNum(v.w,v.n);
            const baseWR=baselineMap?.[k]??null;
            return{
              bucket:k,
              n:v.n,
              wins:v.w,
              losses:v.l,
              WR:_wrPct(v.w,v.n),
              baselineMay14:baseWR!=null?baseWR.toFixed(1)+'%':'—',
              delta:_delta(wr,baseWR),
            };
          })
          .sort((a,b)=>b.n-a.n);
      };
      const _overallW=resolved.filter(e=>e.result==='WIN').length;
      console.group(`%c━━━ Tara Audit Stats ━━━`,'color:#E5C870;font-weight:bold;font-size:13px');
      console.info(`Filter: asset=${_asset}, autoExecOnly=${_autoOnly}, minN=${_minN}`);
      console.info(`Entries: ${filtered.length} total · ${resolved.length} resolved · ${filtered.length-resolved.length} pending/sit-out`);
      console.info(`Overall WR: ${_wrPct(_overallW,resolved.length)} (${_overallW}W / ${resolved.length-_overallW}L)`);
      // ── BY TIER ────────────────────────────────────────────────────────
      console.group('By tier');
      try{console.table(_groupBy(resolved,e=>e.tier||'untiered',_AUDIT_BASELINES.tier));}catch(_){}
      console.groupEnd();
      // ── BY REGIME ──────────────────────────────────────────────────────
      console.group('By regime');
      try{console.table(_groupBy(resolved,e=>e.regime||'unknown'));}catch(_){}
      console.groupEnd();
      // ── BY EDGE BUCKET (Tara conf - Kalshi conf, on Tara's direction) ─
      console.group('By edge bucket — Tara conv minus Kalshi conv, on her dir');
      try{console.table(_groupBy(resolved,e=>{
        const _post=Number(e.posterior),_k=Number(e.kalshiAtLock);
        if(!Number.isFinite(_post)||!Number.isFinite(_k)||!e.dir)return null;
        const _taraConf=e.dir==='UP'?_post:(100-_post);
        const _kalConf=e.dir==='UP'?_k:(100-_k);
        const _edge=_taraConf-_kalConf;
        if(_edge<=-10)return 'edge ≤ -10pt';
        if(_edge<0)return 'edge -10 to 0';
        if(_edge<10)return 'edge 0-10pt';
        if(_edge<20)return 'edge 10-20pt';
        if(_edge<30)return 'edge 20-30pt';
        return 'edge 30+pt';
      },_AUDIT_BASELINES.edge));}catch(_){}
      console.groupEnd();
      // ── BY SESSION ─────────────────────────────────────────────────────
      console.group('By session (London/Asia/NY/OFF)');
      try{console.table(_groupBy(resolved,e=>e.session||'unknown'));}catch(_){}
      console.groupEnd();
      // ── BY WINDOW TYPE ─────────────────────────────────────────────────
      console.group('By window type');
      try{console.table(_groupBy(resolved,e=>e.windowType||'unknown'));}catch(_){}
      console.groupEnd();
      // ── BY ASSET (only meaningful if not pre-filtered to one) ──────────
      if(_asset==='all'){
        console.group('By asset');
        try{console.table(_groupBy(resolved,e=>e.asset||'BTC'));}catch(_){}
        console.groupEnd();
      }
      // ── BY DIRECTION ───────────────────────────────────────────────────
      console.group('By direction');
      try{console.table(_groupBy(resolved,e=>e.dir||'unknown'));}catch(_){}
      console.groupEnd();
      // ── AUTO vs MANUAL (only if not pre-filtered to auto-only) ─────────
      if(!_autoOnly){
        console.group('Auto-exec vs manual');
        try{console.table(_groupBy(resolved,e=>e.autoExec===true?'auto-exec':'manual'));}catch(_){}
        console.groupEnd();
      }
      // ── TIME-CAP-COMMIT SUB-BANDS (V9.19.26 finding) ───────────────────
      const _tcResolved=resolved.filter(e=>e.tier==='time-cap-commit'||e.tier==='timer-commit');
      if(_tcResolved.length>=_minN){
        console.group(`Time-cap-commit sub-bands · n=${_tcResolved.length} (May 14: 90-119s was worst at 54.6%)`);
        try{console.table(_groupBy(_tcResolved,e=>{
          const _sec=Number(e.secondsIntoWindow);
          if(!Number.isFinite(_sec))return null;
          if(_sec<60)return '0-59s';
          if(_sec<90)return '60-89s';
          if(_sec<120)return '90-119s';
          if(_sec<180)return '120-179s';
          return '180s+';
        },_AUDIT_BASELINES.tcBand));}catch(_){}
        console.groupEnd();
      }
      // ── qScore v1 vs v2 MONOTONICITY ─────────────────────────────────
      // If higher score → higher WR consistently in BOTH columns, both
      //   models are calibrated. If v2 shows tighter monotonicity than v1,
      //   v2 is more predictive — graduate it from shadow to primary.
      const _scoreBucket=(s)=>{
        const _n=Number(s);
        if(!Number.isFinite(_n))return null;
        if(_n<20)return '0-19';
        if(_n<40)return '20-39';
        if(_n<60)return '40-59';
        if(_n<80)return '60-79';
        return '80-100';
      };
      const _v1Rows=_groupBy(resolved,e=>_scoreBucket(e.qScore));
      const _v2Rows=_groupBy(resolved,e=>_scoreBucket(e.qScoreV2));
      const _hasV2=_v2Rows.length>0;
      if(_v1Rows.length>0){
        console.group(`Score-bucket monotonicity${_hasV2?' (v1 vs v2)':''}`);
        try{console.info('qScore v1 (current production):');console.table(_v1Rows);}catch(_){}
        if(_hasV2){try{console.info('qScoreV2 (shadow, V9.19.10+):');console.table(_v2Rows);}catch(_){}}
        else{console.info('qScoreV2: no data in log (older entries pre-V9.19.10 don\'t have it)');}
        console.groupEnd();
      }
      console.groupEnd(); // close the outer audit group
      // Return the structured data so it can be assigned to a var for further analysis
      return{
        filter:{asset:_asset,autoExecOnly:_autoOnly,minN:_minN},
        totals:{entries:filtered.length,resolved:resolved.length,wins:_overallW,losses:resolved.length-_overallW,WR:_wrPct(_overallW,resolved.length)},
      };
    }catch(e){console.error('[AuditStats] failed:',e&&e.message);return null;}
  };
  try{console.info('[AuditStats] hook ready — run window.__taraAuditStats() in console');}catch(_){}

  // ═════════════════════════════════════════════════════════════════════════
  // V10.2.13 — TIER × SESSION/HOUR/WINDOW CROSS-TAB AUDITS
  // ═════════════════════════════════════════════════════════════════════════
  // Three new console hooks for testing the hypothesis: does tier performance
  // vary by session-of-day or hour-of-day? If yes, we know which tier to
  // boost when. If no, the optimizer infrastructure stays off — no harm done.
  //
  //   window.__taraTierBySession()  → 4×N table: ASIA/EU/US/OFF × tier
  //   window.__taraTierByHour()     → 24×N table: hour-of-day × tier
  //   window.__taraTierByWindow()   → 2×N table: 5m vs 15m × tier
  //
  // Each cell shows: WR% (n) — and is dimmed if n < minN (default 10).
  // After the table, prints which tier wins each row and by how many points.
  //
  // Options: {minN: 10, autoExecOnly: false, asset: null, windowType: null}
  // ═════════════════════════════════════════════════════════════════════════
  const _readCallLog=()=>{
    try{
      const raw=localStorage.getItem('taraCallLog_v1');
      if(!raw)return null;
      const log=JSON.parse(raw);
      return Array.isArray(log)?log:null;
    }catch(_){return null;}
  };
  const _filterLog=(log,opts)=>{
    const _autoOnly=opts?.autoExecOnly===true;
    const _asset=opts?.asset||null;
    const _windowType=opts?.windowType||null;
    return log.filter(e=>{
      if(!e)return false;
      if(_autoOnly&&!e.autoExec)return false;
      if(_asset&&e.asset!==_asset)return false;
      if(_windowType&&e.windowType!==_windowType)return false;
      return e.result==='WIN'||e.result==='LOSS';
    });
  };
  const _wrCell=(wins,n,minN)=>{
    if(n===0)return{label:'·',raw:null,n:0,dim:true};
    const pct=Math.round((wins/n)*1000)/10;
    return{label:`${pct}% (${n})`,raw:pct,n,dim:n<minN};
  };
  const _printCrossTab=(title,table,rowLabels,colLabels,minN)=>{
    console.group(`%c━━━ ${title} ━━━`,'color:#E5C870;font-weight:bold;font-size:13px');
    // Convert to console.table-friendly shape
    const _rows={};
    rowLabels.forEach(r=>{
      _rows[r]={};
      colLabels.forEach(c=>{
        const cell=table[r]?.[c];
        _rows[r][c]=cell?cell.label:'·';
      });
    });
    console.table(_rows);
    // Best-tier-per-row analysis
    console.info('%cBest tier per row (n ≥ '+minN+'):','color:#A78BFA;font-weight:bold');
    rowLabels.forEach(r=>{
      const cells=colLabels.map(c=>({col:c,...table[r]?.[c]}));
      const valid=cells.filter(c=>c&&c.raw!=null&&c.n>=minN);
      if(valid.length===0){
        console.info(`  ${r}: (no cells with n≥${minN})`);
        return;
      }
      const best=valid.reduce((a,b)=>b.raw>a.raw?b:a);
      const worst=valid.reduce((a,b)=>b.raw<a.raw?b:a);
      const gap=best.raw-worst.raw;
      const gapStr=gap>=10?`%c+${gap.toFixed(1)}pt gap`:`+${gap.toFixed(1)}pt gap`;
      const style=gap>=10?'color:rgb(110,231,183);font-weight:bold':'color:rgba(232,233,228,0.55)';
      if(gap>=10){
        console.info(`  ${r}: ${best.col} wins (${best.label}) vs ${worst.col} (${worst.label}) — ${gapStr}`,style);
      }else{
        console.info(`  ${r}: ${best.col} (${best.label}) — gap only +${gap.toFixed(1)}pt vs ${worst.col} (${worst.label})`);
      }
    });
    console.groupEnd();
  };
  const _buildCrossTab=(entries,rowFn,colFn)=>{
    const _table={};
    const _rowsSet=new Set();
    const _colsSet=new Set();
    entries.forEach(e=>{
      const r=rowFn(e);
      const c=colFn(e);
      if(r==null||c==null||r===''||c==='')return;
      _rowsSet.add(r);_colsSet.add(c);
      if(!_table[r])_table[r]={};
      if(!_table[r][c])_table[r][c]={wins:0,n:0};
      _table[r][c].n++;
      if(e.result==='WIN')_table[r][c].wins++;
    });
    return{table:_table,rows:Array.from(_rowsSet),cols:Array.from(_colsSet)};
  };
  const _normalizeTier=(t)=>{
    if(!t)return 'untiered';
    const s=String(t).toLowerCase();
    // Collapse variants: tape-led, tape → 'tape'; structural-led, structural → 'structural'; etc.
    if(s.includes('super')||s.includes('confluence'))return 'confluence';
    if(s.includes('structural'))return 'structural';
    if(s.includes('tape'))return 'tape';
    if(s.includes('time-cap')||s.includes('timer'))return 'time-cap';
    if(s.includes('single'))return 'single';
    return s;
  };

  window.__taraTierBySession=(opts={})=>{
    const minN=Number(opts.minN)||10;
    const log=_readCallLog();
    if(!log){console.warn('[TierBySession] no call log');return null;}
    const entries=_filterLog(log,opts);
    const{table,rows,cols}=_buildCrossTab(entries,e=>e.session||'unknown',e=>_normalizeTier(e.tier));
    // Build display table with WR cells
    const _displayTable={};
    rows.forEach(r=>{
      _displayTable[r]={};
      cols.forEach(c=>{
        const cell=table[r]?.[c];
        _displayTable[r][c]=cell?_wrCell(cell.wins,cell.n,minN):{label:'·',n:0,dim:true};
      });
    });
    // Sort: standard session order, then tiers by overall sample size desc
    const _sessionOrder=['ASIA','EU','US','OFF-HOURS','unknown'];
    const _orderedRows=[..._sessionOrder.filter(s=>rows.includes(s)),...rows.filter(r=>!_sessionOrder.includes(r))];
    const _tierTotals={};
    cols.forEach(c=>{_tierTotals[c]=rows.reduce((sum,r)=>sum+(table[r]?.[c]?.n||0),0);});
    const _orderedCols=cols.slice().sort((a,b)=>_tierTotals[b]-_tierTotals[a]);
    _printCrossTab(`Tier × Session (n=${entries.length} resolved trades, minN=${minN})`,_displayTable,_orderedRows,_orderedCols,minN);
    return{table:_displayTable,rows:_orderedRows,cols:_orderedCols};
  };

  window.__taraTierByHour=(opts={})=>{
    const minN=Number(opts.minN)||10;
    const log=_readCallLog();
    if(!log){console.warn('[TierByHour] no call log');return null;}
    const entries=_filterLog(log,opts);
    const{table,rows,cols}=_buildCrossTab(entries,
      e=>{
        const t=e.timestampISO||e.timestamp||null;
        if(!t)return null;
        const d=new Date(t);
        if(!d.getTime())return null;
        const h=d.getUTCHours();
        return`${String(h).padStart(2,'0')}:00 UTC`;
      },
      e=>_normalizeTier(e.tier)
    );
    const _displayTable={};
    rows.forEach(r=>{
      _displayTable[r]={};
      cols.forEach(c=>{
        const cell=table[r]?.[c];
        _displayTable[r][c]=cell?_wrCell(cell.wins,cell.n,minN):{label:'·',n:0,dim:true};
      });
    });
    const _orderedRows=rows.slice().sort();
    const _tierTotals={};
    cols.forEach(c=>{_tierTotals[c]=rows.reduce((sum,r)=>sum+(table[r]?.[c]?.n||0),0);});
    const _orderedCols=cols.slice().sort((a,b)=>_tierTotals[b]-_tierTotals[a]);
    _printCrossTab(`Tier × Hour-of-day UTC (n=${entries.length} resolved trades, minN=${minN})`,_displayTable,_orderedRows,_orderedCols,minN);
    return{table:_displayTable,rows:_orderedRows,cols:_orderedCols};
  };

  window.__taraTierByWindow=(opts={})=>{
    const minN=Number(opts.minN)||10;
    const log=_readCallLog();
    if(!log){console.warn('[TierByWindow] no call log');return null;}
    const entries=_filterLog(log,opts);
    const{table,rows,cols}=_buildCrossTab(entries,e=>e.windowType||'unknown',e=>_normalizeTier(e.tier));
    const _displayTable={};
    rows.forEach(r=>{
      _displayTable[r]={};
      cols.forEach(c=>{
        const cell=table[r]?.[c];
        _displayTable[r][c]=cell?_wrCell(cell.wins,cell.n,minN):{label:'·',n:0,dim:true};
      });
    });
    const _orderedRows=['15m','5m'].filter(r=>rows.includes(r)).concat(rows.filter(r=>r!=='15m'&&r!=='5m'));
    const _tierTotals={};
    cols.forEach(c=>{_tierTotals[c]=rows.reduce((sum,r)=>sum+(table[r]?.[c]?.n||0),0);});
    const _orderedCols=cols.slice().sort((a,b)=>_tierTotals[b]-_tierTotals[a]);
    _printCrossTab(`Tier × Window-type (n=${entries.length} resolved trades, minN=${minN})`,_displayTable,_orderedRows,_orderedCols,minN);
    return{table:_displayTable,rows:_orderedRows,cols:_orderedCols};
  };

  try{console.info('[V10.2.13] tier cross-tab hooks ready — __taraTierBySession() / __taraTierByHour() / __taraTierByWindow()');}catch(_){}
}

// ═══════════════════════════════════════════════════════════════════════════
// V10.2.4 — AUTO-EXEC EVENT LOG
// ═══════════════════════════════════════════════════════════════════════════
// Persistent log of every auto-exec decision: placed, filled, exited, blocked,
//   error. Surfaces what's ACTUALLY happening with auto-exec — including all
//   the times it sat out and why. Without this, you only see settled trades
//   in the call log, not the (much larger) population of attempts and skips.
//
// Stored in localStorage at 'taraAutoExecLog_v1'. Cap 500 events (auto-prunes
//   oldest on overflow). Each event has timestamp, type, asset, windowId, and
//   type-specific fields (limit, fill price, exit reason, block guard, etc.).
//
// Console hooks:
//   window.__taraAutoExecLog()                  → print today's events
//   window.__taraAutoExecLog({n:50})            → last N events
//   window.__taraAutoExecLog({type:'blocked'})  → only block events
//   window.__taraAutoExecLog({type:'placed'})   → only placement events
//   window.__taraAutoExecLog({asset:'BTC'})     → filter to one asset
//   window.__taraAutoExecLog({raw:true})        → return full array, no print
//   window.__taraAutoExecLogClear()             → wipe (asks for confirmation)
const AUTO_EXEC_LOG_CAP=500;
const AUTO_EXEC_LOG_KEY='taraAutoExecLog_v1';
const _autoExecLogPush=(event)=>{
  try{
    const _raw=localStorage.getItem(AUTO_EXEC_LOG_KEY);
    const _arr=_raw?JSON.parse(_raw):[];
    if(!Array.isArray(_arr))return;
    const _e={id:Date.now()+Math.random(),ts:Date.now(),...event};
    _arr.push(_e);
    if(_arr.length>AUTO_EXEC_LOG_CAP)_arr.splice(0,_arr.length-AUTO_EXEC_LOG_CAP);
    localStorage.setItem(AUTO_EXEC_LOG_KEY,JSON.stringify(_arr));
  }catch(_){}
};
// V10.2.6 — DEDUPE BLOCKED EVENTS to stop log spam. The auto-exec entry effect
//   re-evaluates ~1Hz (on every snapshot tick) and was pushing a 'blocked' event
//   per tick when a guard fired — flooding the 500-event FIFO buffer with
//   duplicates and EVICTING the actually-interesting events (placed/filled/exited).
//   May 14 user log: 500/500 entries were 'window-cap' blocks on a single window;
//   the two manual 'placed' events from that window had been pushed out.
//
//   Fix: per-window+guard+asset dedupe. First block of a given (guard, wid, asset)
//   logs; subsequent identical blocks are silently dropped. Module-level Set —
//   survives renders but resets on full page refresh (acceptable; refreshing is
//   itself a fresh diagnostic context). Self-prunes at 2000 entries.
const _AUTO_EXEC_BLOCK_DEDUP=new Set();
const _autoExecLogPushBlockOnce=(payload)=>{
  try{
    const _key=`${payload&&payload.guard||'?'}|${payload&&payload.windowId||'?'}|${payload&&payload.asset||'?'}|${payload&&payload.dir||'?'}`;
    if(_AUTO_EXEC_BLOCK_DEDUP.has(_key))return;
    _AUTO_EXEC_BLOCK_DEDUP.add(_key);
    if(_AUTO_EXEC_BLOCK_DEDUP.size>2000)_AUTO_EXEC_BLOCK_DEDUP.clear();
    _autoExecLogPush(payload);
  }catch(_){}
};
const _autoExecLogGet=()=>{
  try{
    const _raw=localStorage.getItem(AUTO_EXEC_LOG_KEY);
    return _raw?JSON.parse(_raw):[];
  }catch(_){return[];}
};
if(typeof window!=='undefined'){
  window.__taraAutoExecLog=(opts={})=>{
    try{
      const _log=_autoExecLogGet();
      let _filtered=_log;
      if(opts.type)_filtered=_filtered.filter(e=>e.type===opts.type);
      if(opts.asset)_filtered=_filtered.filter(e=>e.asset===opts.asset);
      if(opts.todayOnly){
        const _todayStart=new Date();_todayStart.setHours(0,0,0,0);
        _filtered=_filtered.filter(e=>e.ts>=_todayStart.getTime());
      }
      const _n=Math.max(1,Number(opts.n)||_filtered.length);
      _filtered=_filtered.slice(-_n);
      if(opts.raw)return _filtered;
      console.group(`%c━━━ Tara Auto-Exec Event Log ━━━`,'color:#E5C870;font-weight:bold;font-size:13px');
      console.info(`Showing: ${_filtered.length} events (filter: ${opts.type||'all types'}, ${opts.asset||'all assets'})`);
      // Summary by type
      const _byType={};
      _filtered.forEach(e=>{if(!_byType[e.type])_byType[e.type]=[];_byType[e.type].push(e);});
      const _summary=Object.entries(_byType).map(([type,events])=>({
        type,count:events.length,
        firstAt:events.length?new Date(events[0].ts).toLocaleString():'',
        lastAt:events.length?new Date(events[events.length-1].ts).toLocaleString():'',
      }));
      console.group('Summary by type');
      try{console.table(_summary);}catch(_){}
      console.groupEnd();
      // Block reasons breakdown (most informative for "why didn't it fire")
      const _blocks=_filtered.filter(e=>e.type==='blocked');
      if(_blocks.length>0){
        const _byGuard={};
        _blocks.forEach(e=>{const g=e.guard||'unknown';_byGuard[g]=(_byGuard[g]||0)+1;});
        console.group(`Block reasons (n=${_blocks.length})`);
        try{console.table(Object.entries(_byGuard).map(([guard,count])=>({guard,count})).sort((a,b)=>b.count-a.count));}catch(_){}
        console.groupEnd();
      }
      // Full timeline (most recent first)
      console.group(`Timeline (${_filtered.length} events, most recent first)`);
      try{console.table(_filtered.slice().reverse().map(e=>({
        time:new Date(e.ts).toLocaleTimeString(),
        type:e.type,
        asset:e.asset||'',
        dir:e.dir||'',
        wid:(e.windowId||'').split('-').pop()?.slice(-12)||'',
        details:e.exitReason||e.blockReason||e.errorMsg||(e.limitCents?`${e.limitCents}¢`:'')||(e.fillPriceCents?`fill ${e.fillPriceCents}¢`:'')||'',
      })));}catch(_){}
      console.groupEnd();
      console.groupEnd();
      return{count:_filtered.length,byType:_byType};
    }catch(e){console.error('[AutoExecLog] failed:',e&&e.message);return null;}
  };
  window.__taraAutoExecLogClear=()=>{
    try{
      if(!confirm('Wipe all auto-exec event log entries? This cannot be undone.'))return;
      localStorage.removeItem(AUTO_EXEC_LOG_KEY);
      console.info('[AutoExecLog] cleared');
    }catch(_){}
  };
  try{console.info('[AutoExecLog] hook ready — run window.__taraAutoExecLog() in console');}catch(_){}
}

// Deterministic ID for the current trading window (UTC ISO of window-open boundary).
// Refresh during the same window → same ID → restore the same lock.
const computeWindowId=(windowType)=>{
  const winMs=windowType==='15m'?900000:300000;
  const bucketMs=Math.floor(Date.now()/winMs)*winMs;
  return `${windowType}-${new Date(bucketMs).toISOString()}`;
};

// ═══════════════════════════════════════════════════════════════════════════
// V9.19.11: getTaraDirection — central helper for resolving "what direction
//   does Tara think the price is going?" Handles the V9.17.22/V9.18.7 snapshot
//   vs. lock signal-source semantics in ONE place. Returns null when Tara has
//   no opinion.
//
// Background: Tara holds direction state in several refs that can disagree:
//   • taraCallSnapshotRef.current.call — the public 67% WR snapshot (preferred)
//   • lockedCallRef.current.dir — internal engine lock (fires earlier)
//   • engineLockedDirRef.current — derived signal (alias of lock)
//   • taraCall (state) — display-layer copy of snapshot
//   • analysis.lockInfo.dir — built from lockedCallRef
//   • autoOrderState.dir — what was actually placed
//   • scalperRead.dir — independent scalper engine (NOT Tara — different model)
//
// V9.18.7 patched ONE display site to respect autoExecSettings.signalSource.
// This helper centralizes that decision so future call sites can be migrated
// over time without re-deriving the precedence logic at each one.
//
// Inputs:
//   • snapshot — taraCallSnapshotRef.current (the engine's "settled call")
//   • lock — lockedCallRef.current (the engine's "live lock")
//   • signalSource — 'snapshot' (default, V9.17.22) | 'lock'
//
// Returns:
//   • dir — 'UP' | 'DOWN' | null
//   • source — which ref the direction came from (for diagnostics)
//
// Future migrations (separate sessions):
//   • analysis.lockInfo construction → use this helper
//   • UI ticket rendering → use this helper
//   • taraCall display → use this helper
//   • autoOrderState.dir comparison → use this helper
//   At each migration, verify behavior unchanged via build + spot-check.
// ═══════════════════════════════════════════════════════════════════════════
const getTaraDirection=({snapshot,lock,signalSource}={})=>{
  const _snapDir=snapshot?.call==='UP'||snapshot?.call==='DOWN'?snapshot.call:null;
  const _lockDir=lock?.dir==='UP'||lock?.dir==='DOWN'?lock.dir:null;
  const _src=signalSource==='lock'?'lock':'snapshot';
  // Snapshot mode (default): prefer snapshot, fall back to lock if no snapshot.
  // Lock mode: prefer lock, fall back to snapshot if no lock.
  let dir=null;
  let source=null;
  if(_src==='lock'){
    if(_lockDir){dir=_lockDir;source='lock';}
    else if(_snapDir){dir=_snapDir;source='snapshot(fallback)';}
  } else {
    if(_snapDir){dir=_snapDir;source='snapshot';}
    else if(_lockDir){dir=_lockDir;source='lock(fallback)';}
  }
  return{dir,source};
};

