// MATH & INDICATORS (V99 ENHANCED)
// ═══════════════════════════════════════
const formatUSD=(val)=>{const abs=Math.abs(val);if(abs>=1e6)return(val/1e6).toFixed(2)+'M';if(abs>=1e3)return(val/1e3).toFixed(1)+'K';return val.toFixed(0);};
// V5.7.3: Single source of truth for duration formatting. Returns "Xs" under 60s,
//   "Mm SSs" otherwise. Handles null/NaN gracefully. Used everywhere a countdown is shown.
// ═══════════════════════════════════════
// V9.2.2: TARA ML LAYER — in-browser logistic regression
// ═══════════════════════════════════════
// Trains on signalScoresAtLock features from resolved trades. Outputs a
// predicted WIN probability that feeds into the posterior as an additional
// signal (+/-10 pts max). Activates when ≥50 resolved trades with signal
// data exist. Retrains on every new resolved trade.
//
// Features: gap, momentum, flow, structure, technical, regime, rangePosition,
//   reversal, meanReversion, crossAsset + regime_encoded + channelPos + atrBps.
// Target: 1 = WIN, 0 = LOSS.
// Model: L2-regularized logistic regression (no external libraries).
const TARA_ML_FEATURES=['gap','momentum','flow','structure','technical','regime','rangePosition','reversal','meanReversion','crossAsset'];
const TARA_ML_MIN_TRADES=50;
const TARA_ML_LEARNING_RATE=0.01;
const TARA_ML_EPOCHS=100;
const TARA_ML_L2=0.001;

const _sigmoid=(z)=>1/(1+Math.exp(-Math.max(-20,Math.min(20,z))));

const taraMLExtractFeatures=(entry)=>{
  const sigs=entry.signalScoresAtLock||{};
  const features=TARA_ML_FEATURES.map(k=>Number(sigs[k])||0);
  // Extra features: channelPos (0-1), atrBps (normalized), posterior at lock
  features.push(Number(entry.calibratedPosteriorAtLock)||50);
  features.push(Number(entry.atrBpsAtLock)||15);
  // Regime one-hot: 5 regimes
  const _regimes=['TRENDING UP','TRENDING DOWN','RANGE-CHOP','SHORT SQUEEZE','HIGH VOL CHOP'];
  _regimes.forEach(r=>features.push(entry.regime===r?1:0));
  return features;
};

const taraMLTrain=(entries)=>{
  // Filter to resolved trades with signal data
  const data=entries.filter(e=>e&&(e.result==='WIN'||e.result==='LOSS')&&e.signalScoresAtLock);
  if(data.length<TARA_ML_MIN_TRADES)return null;
  const nFeatures=taraMLExtractFeatures(data[0]).length;
  // Initialize weights to small random values
  let weights=new Array(nFeatures).fill(0).map(()=>(Math.random()-0.5)*0.1);
  let bias=0;
  // Normalize features: compute mean + std per feature
  const sums=new Array(nFeatures).fill(0);
  const sqSums=new Array(nFeatures).fill(0);
  const allX=data.map(e=>taraMLExtractFeatures(e));
  allX.forEach(x=>x.forEach((v,i)=>{sums[i]+=v;sqSums[i]+=v*v;}));
  const means=sums.map(s=>s/data.length);
  const stds=sqSums.map((sq,i)=>{const v=sq/data.length-means[i]*means[i];return Math.sqrt(Math.max(1e-8,v));});
  const normX=allX.map(x=>x.map((v,i)=>(v-means[i])/stds[i]));
  const y=data.map(e=>e.result==='WIN'?1:0);
  // SGD with L2 regularization
  for(let epoch=0;epoch<TARA_ML_EPOCHS;epoch++){
    // Shuffle indices
    const idx=[...Array(data.length).keys()];
    for(let i=idx.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[idx[i],idx[j]]=[idx[j],idx[i]];}
    let totalLoss=0;
    for(const i of idx){
      const x=normX[i];
      const z=x.reduce((s,v,j)=>s+v*weights[j],bias);
      const pred=_sigmoid(z);
      const err=pred-y[i];
      totalLoss+=-y[i]*Math.log(pred+1e-8)-(1-y[i])*Math.log(1-pred+1e-8);
      // Update weights with L2
      for(let j=0;j<nFeatures;j++){
        weights[j]-=TARA_ML_LEARNING_RATE*(err*x[j]+TARA_ML_L2*weights[j]);
      }
      bias-=TARA_ML_LEARNING_RATE*err;
    }
  }
  // Compute training accuracy
  let correct=0;
  normX.forEach((x,i)=>{
    const z=x.reduce((s,v,j)=>s+v*weights[j],bias);
    const pred=_sigmoid(z)>=0.5?1:0;
    if(pred===y[i])correct++;
  });
  const accuracy=correct/data.length;
  // Feature importance: absolute weight values
  const importance=TARA_ML_FEATURES.map((name,i)=>({name,weight:weights[i],absWeight:Math.abs(weights[i])}));
  importance.sort((a,b)=>b.absWeight-a.absWeight);
  return{weights,bias,means,stds,nFeatures,nTrades:data.length,accuracy,importance,trainedAt:Date.now()};
};

const taraMLPredict=(model,entry)=>{
  if(!model||!model.weights)return null;
  const raw=taraMLExtractFeatures(entry);
  if(raw.length!==model.nFeatures)return null;
  const norm=raw.map((v,i)=>(v-(model.means[i]||0))/(model.stds[i]||1));
  const z=norm.reduce((s,v,j)=>s+v*(model.weights[j]||0),model.bias||0);
  return _sigmoid(z); // 0-1 probability of WIN
};


// V9.2.3: STALE ENTRY CLEANUP — scans call log for missing/broken fields, backfills
//   what's derivable, removes genuinely broken entries, deduplicates.
const taraCleanupLog=(log)=>{
  if(!Array.isArray(log)||log.length===0)return{cleaned:log,report:{removed:0,backfilled:0,deduped:0,details:[]}};
  const report={removed:0,backfilled:0,deduped:0,details:[]};
  let entries=[...log];
  // Pass 1: Remove genuinely broken entries (no windowId, no time/id)
  const beforeLen=entries.length;
  entries=entries.filter(e=>{
    if(!e)return false;
    if(!e.windowId&&!e.id&&!e.time){report.details.push('Removed: no windowId/id/time');return false;}
    return true;
  });
  report.removed=beforeLen-entries.length;
  // Pass 2: Backfill derivable fields
  entries=entries.forEach?entries.map(e=>{
    let changed=false;
    // Asset from strike
    if(!e.asset&&e.strike){
      e.asset=e.strike>=10000?'BTC':'ETH';
      changed=true;
    }
    if(!e.asset)e.asset='BTC';
    // closingGapBps from strike + closingPrice
    if(e.closingGapBps==null&&e.strike>0&&e.closingPrice>0){
      e.closingGapBps=Math.round(((e.closingPrice-e.strike)/e.strike)*10000*100)/100;
      changed=true;
    }
    // outcomeDir from closingPrice vs strike
    if(!e.outcomeDir&&e.strike>0&&e.closingPrice>0&&e.closingPrice!==e.strike){
      e.outcomeDir=e.closingPrice>e.strike?'UP':'DOWN';
      changed=true;
    }
    // phase from timestamp
    if(!e.phase&&(e.id||e.time)){
      try{
        const dt=new Date(e.id||e.time);
        const h=dt.getUTCHours(),m=dt.getUTCMinutes();
        if(typeof getPhaseKey==='function')e.phase=getPhaseKey(h,m);
        changed=true;
      }catch(_){}
    }
    // session from phase
    if(!e.session&&e.phase){
      const pk=e.phase;
      if(pk==='ASIA_OPEN'||pk==='ASIA_LATE')e.session='ASIA';
      else if(pk==='EU_PREOPEN'||pk==='EU_OPEN')e.session='EU';
      else if(pk.startsWith('NY_'))e.session='US';
      else e.session='OFF-HOURS';
      changed=true;
    }
    // windowType default
    if(!e.windowType)e.windowType='15m';
    if(changed)report.backfilled++;
    return e;
  }):entries;
  // Pass 3: Deduplicate by asset|windowId|windowType
  const seen=new Map();
  const beforeDedup=entries.length;
  entries.forEach(e=>{
    const k=(e.asset||'BTC')+'|'+(e.windowId||'')+'|'+(e.windowType||'');
    const existing=seen.get(k);
    if(!existing){seen.set(k,e);return;}
    // Keep resolved over unresolved, older id over newer
    if(!existing.result&&e.result){seen.set(k,e);return;}
    if(existing.result&&!e.result)return;
    if((e.id||0)<(existing.id||0))seen.set(k,e);
  });
  entries=Array.from(seen.values()).sort((a,b)=>(a.id||0)-(b.id||0));
  report.deduped=beforeDedup-entries.length;
  return{cleaned:entries,report};
};

// V9.2.3: STREAK DETECTION — computes current win/loss streak from recent trades.
const computeStreak=(log,asset)=>{
  const recent=[...(log||[])].filter(e=>e&&(e.result==='WIN'||e.result==='LOSS')&&(e.asset||'BTC')===asset).sort((a,b)=>(b.id||0)-(a.id||0));
  if(recent.length===0)return{type:null,count:0};
  const firstResult=recent[0].result;
  let count=0;
  for(const e of recent){
    if(e.result===firstResult)count++;
    else break;
  }
  return{type:firstResult,count};
};

// V9.14: ECONOMIC CALENDAR BLACKOUT
//   Major US macro events reliably create 1-3 minutes of directional spike followed
//   by 5-15 minutes of high volatility. During that window, Tara's signals (which
//   are calibrated to "normal" market conditions) become unreliable — patterns
//   that fired 10 seconds before the event are wiped out by the post-event flush.
//
//   Strategy: hardcoded major US events. Within ±15 minutes of any event, return
//   a non-zero risk score that the engine reads as a confidence dampener (not a
//   block — user said no gates). The dampener pushes totalScore TOWARD zero,
//   making Tara more reluctant to commit either direction.
//
//   Events tracked (UTC times, converted to EST/EDT inside the check):
//   - NFP: First Friday of each month, 8:30 AM ET
//   - CPI: Mid-month (10-15), usually 8:30 AM ET (Tue/Wed)
//   - FOMC: 8x per year, 2:00 PM ET (rate decision)
//   - Powell press conf: 30 min after FOMC
//   - Jobless claims: Every Thursday 8:30 AM ET
//   - PPI: Day after CPI, 8:30 AM ET
//
// Why hardcoded vs API: Calendar APIs (TradingEconomics, ForexFactory) require
//   API keys, have rate limits, and add a network failure mode. The major events
//   that move crypto are deterministic enough that hardcoded dates work.
//   Calendar can be refreshed yearly by updating this constant.
//
// Coverage tradeoff: misses surprise events (geopolitical, exchange hacks,
//   regulator actions). Those need news/twitter monitoring, which is a separate
//   ship. This catches the SCHEDULED moves which are 60-70% of macro-shock risk.
const computeEconCalendarRisk=()=>{
  const _now=new Date();
  const _utcHour=_now.getUTCHours();
  const _utcMin=_now.getUTCMinutes();
  const _utcDay=_now.getUTCDay(); // 0=Sun, 1=Mon, ... 4=Thu, 5=Fri
  const _utcDate=_now.getUTCDate();
  const _utcMonth=_now.getUTCMonth(); // 0-11
  // DST approximation: Mar-Nov. ET = UTC-4 (DST) or UTC-5 (standard)
  const _isDst=_utcMonth>=2&&_utcMonth<=10;
  const _etOffset=_isDst?4:5;
  // Compute "minutes-since-midnight ET" for the event-time math
  const _etMinutes=((_utcHour-_etOffset)+24)%24*60+_utcMin;
  // Helper: minutes from a target ET time (HH:MM in ET)
  const _minsFromEtTime=(etHour,etMin)=>{
    const _target=etHour*60+etMin;
    return _etMinutes-_target;
  };
  // 1. NFP: first Friday of the month, 8:30 AM ET
  //    First Friday = Fri AND (date 1-7)
  const _isFirstFriday=_utcDay===5&&_utcDate<=7;
  if(_isFirstFriday){
    const _diff=_minsFromEtTime(8,30);
    if(_diff>=-15&&_diff<=15){
      return{risk:25,event:'NFP (Non-Farm Payrolls)',etTime:'8:30 AM ET',minsOffset:_diff};
    }
  }
  // 2. FOMC: 2:00 PM ET on known dates. Hardcode 2026 schedule:
  //    Jan 28, Mar 18, Apr 29, Jun 17, Jul 29, Sep 16, Oct 28, Dec 9
  const _fomcDates2026=[
    {m:0,d:28},{m:2,d:18},{m:3,d:29},{m:5,d:17},
    {m:6,d:29},{m:8,d:16},{m:9,d:28},{m:11,d:9},
  ];
  const _isFomc=_fomcDates2026.some(e=>e.m===_utcMonth&&e.d===_utcDate);
  if(_isFomc){
    const _diff2pm=_minsFromEtTime(14,0);
    if(_diff2pm>=-15&&_diff2pm<=15){
      return{risk:35,event:'FOMC Rate Decision',etTime:'2:00 PM ET',minsOffset:_diff2pm};
    }
    const _diff230=_minsFromEtTime(14,30);
    if(_diff230>=-5&&_diff230<=30){
      return{risk:30,event:'Powell Press Conference',etTime:'2:30 PM ET',minsOffset:_diff230};
    }
  }
  // 3. CPI: mid-month (typically 10-15th), 8:30 AM ET, weekday
  //    Approximate window: 9th-16th, any weekday
  if(_utcDate>=9&&_utcDate<=16&&_utcDay>=1&&_utcDay<=5){
    const _diff=_minsFromEtTime(8,30);
    if(_diff>=-15&&_diff<=15){
      return{risk:25,event:'CPI/Inflation Print (likely)',etTime:'8:30 AM ET',minsOffset:_diff};
    }
  }
  // 4. PPI: day after CPI, similar window
  if(_utcDate>=10&&_utcDate<=17&&_utcDay>=1&&_utcDay<=5){
    const _diff=_minsFromEtTime(8,30);
    if(_diff>=-10&&_diff<=10){
      return{risk:15,event:'PPI (likely)',etTime:'8:30 AM ET',minsOffset:_diff};
    }
  }
  // 5. Jobless claims: Thursday 8:30 AM ET
  if(_utcDay===4){
    const _diff=_minsFromEtTime(8,30);
    if(_diff>=-10&&_diff<=10){
      return{risk:12,event:'Weekly Jobless Claims',etTime:'8:30 AM ET',minsOffset:_diff};
    }
  }
  return{risk:0,event:null,etTime:null,minsOffset:null};
};

// V9.14: SPOT vs PERP DIVERGENCE HOOK
//   Polls Coinbase BTC-USD spot every 10 seconds, compares against the perp
//   mark price (from bloomberg). When perp trades meaningfully above spot
//   (positive premium), leveraged longs are crowded → vulnerable to liq cascade.
//   When perp trades meaningfully below spot (discount), shorts are crowded →
//   squeeze risk.
//
//   Returns: {divBps, perpAbove, spot, perp, lastUpdate, status}
//     divBps: positive = perp premium (longs crowded), negative = perp discount (shorts crowded)
//     perpAbove: bool — perp > spot
const useSpotPerpDivergence=(currentAsset,bloomberg)=>{
  const[data,setData]=React.useState({divBps:0,spot:0,perp:0,perpAbove:false,lastUpdate:0,status:'init'});
  React.useEffect(()=>{
    if(!currentAsset)return;
    const _symbol=currentAsset==='BTC'?'BTC-USD':'ETH-USD';
    const f=async()=>{
      try{
        // Coinbase public ticker — no auth needed, no rate limit issues
        const r=await fetch(`https://api.coinbase.com/v2/prices/${_symbol}/spot`);
        if(!r.ok)return;
        const j=await r.json();
        const _spot=parseFloat(j?.data?.amount);
        if(!Number.isFinite(_spot)||_spot<=0)return;
        const _perp=bloomberg?.markPrice||bloomberg?.indexPrice||0;
        if(_perp<=0){
          setData(prev=>({...prev,spot:_spot,lastUpdate:Date.now(),status:'no-perp'}));
          return;
        }
        const _divBps=((_perp-_spot)/_spot)*10000;
        setData({divBps:_divBps,spot:_spot,perp:_perp,perpAbove:_perp>_spot,lastUpdate:Date.now(),status:'live'});
      }catch(_){
        setData(prev=>({...prev,status:'error'}));
      }
    };
    f();
    const iv=setInterval(f,10000);
    return()=>clearInterval(iv);
  },[currentAsset,bloomberg?.markPrice,bloomberg?.indexPrice]);
  return data;
};

// V9.13: ADAPTIVE SCHEDULE — derived from user's own 536-trade history.
//   Each EST hour mapped to: status (TRADE / SKIP / OBSERVE), recommended dial,
//   and the historical win rate that justifies the recommendation. Status drives
//   the auto-dial logic and the schedule UI strip.
//
//   Status meanings:
//     TRADE   = green zone, historical WR ≥68% — go active
//     OBSERVE = neutral zone, WR 55-67% — small size or skip
//     SKIP    = red zone, WR <55% — don't trade unless very high conviction
//
//   Dial recommendations encode session-specific aggressiveness:
//     45 = patient (require strong setup)
//     50 = balanced (default)
//     55 = slightly aggressive (catch fast moves in slow sessions)
//
//   The auto-dial logic in MarketContextStrip blends THIS schedule with live
//   volatility (velocity/amplitude/ATR) and recent streak. Schedule is the
//   STARTING POINT, then live conditions push the final dial.
const TARA_SCHEDULE_BY_EST_HOUR={
  0:{status:'TRADE',dial:50,wr:73,note:'Asia open — your strongest window'},
  1:{status:'TRADE',dial:50,wr:73,note:'Asia mid — steady micro-trends'},
  2:{status:'TRADE',dial:50,wr:73,note:'Asia mid — clean signals'},
  3:{status:'TRADE',dial:50,wr:73,note:'Asia late — still strong'},
  4:{status:'TRADE',dial:50,wr:70,note:'London pre-open lead-in'},
  5:{status:'TRADE',dial:50,wr:70,note:'London pre-open'},
  6:{status:'OBSERVE',dial:55,wr:60,note:'London quiet lull — selective'},
  7:{status:'OBSERVE',dial:55,wr:60,note:'Bridge to US wake — few setups'},
  8:{status:'TRADE',dial:50,wr:68,note:'EU/US overlap begins'},
  9:{status:'TRADE',dial:50,wr:68,note:'US wake-up — real positioning'},
  10:{status:'TRADE',dial:50,wr:68,note:'US morning — best US window'},
  11:{status:'OBSERVE',dial:55,wr:58,note:'Pre-lunch transition'},
  12:{status:'SKIP',dial:60,wr:31,note:'US lunch lull — algo noise dominates'},
  13:{status:'SKIP',dial:60,wr:31,note:'US lunch — skip unless very confident'},
  14:{status:'SKIP',dial:55,wr:55,note:'US afternoon chop'},
  15:{status:'SKIP',dial:55,wr:55,note:'US afternoon — equity influence'},
  16:{status:'SKIP',dial:55,wr:55,note:'US afternoon — liquidity gaps'},
  17:{status:'SKIP',dial:55,wr:50,note:'US close transition'},
  18:{status:'SKIP',dial:55,wr:50,note:'US close — false moves'},
  19:{status:'OBSERVE',dial:55,wr:60,note:'Asia pre-open bridge'},
  20:{status:'TRADE',dial:50,wr:71,note:'Late US + Asia open'},
  21:{status:'TRADE',dial:50,wr:71,note:'Late evening — directional'},
  22:{status:'TRADE',dial:50,wr:71,note:'Asia ramp-up'},
  23:{status:'TRADE',dial:50,wr:73,note:'Asia evening — strong window'},
};

// V9.13: get the current EST hour. Reads system time and applies UTC-5 offset
//   (or UTC-4 during US daylight saving). We approximate DST as Mar-Nov; close
//   enough for hour-bucket recommendations. The library doesn't need exactness.
const _getEstHour=()=>{
  const d=new Date();
  const _month=d.getUTCMonth(); // 0-11
  const _dstActive=_month>=2&&_month<=10; // approx Mar-Nov
  const _offset=_dstActive?4:5;
  return((d.getUTCHours()-_offset)+24)%24;
};

// V9.13: smart-adaptive dial recommendation.
//   Combines four inputs in order of priority:
//     1. Schedule recommendation for the current EST hour
//     2. Streak adjustment (wins/losses in a row)
//     3. Live volatility (velocity/amplitude/ATR) — existing logic
//     4. Today's intra-session WR (if 5+ resolved trades available)
//
//   Returns: { dial: number, reasoning: string[], status: 'TRADE'|'OBSERVE'|'SKIP' }
//   Reasoning is an array of human-readable strings explaining each adjustment,
//   so the UI can show why the dial landed where it did.
const computeAdaptiveDial=({analysis,streak,todaySessionWR,todaySessionN})=>{
  const _hour=_getEstHour();
  const _slot=TARA_SCHEDULE_BY_EST_HOUR[_hour]||{status:'OBSERVE',dial:50,wr:60,note:''};
  const reasoning=[`Hour ${_hour}:00 EST → ${_slot.status} (historical ${_slot.wr}% WR)`];
  let dial=_slot.dial;
  // Streak adjustments — apply on top of the scheduled base
  if(streak&&streak.type==='WIN'&&streak.count>=4){
    dial+=5;
    reasoning.push(`${streak.count}W streak — dial +5 (don't get greedy, slow down)`);
  } else if(streak&&streak.type==='LOSS'&&streak.count>=3){
    dial+=10;
    reasoning.push(`${streak.count}L streak — dial +10 (patient, demand stronger setup)`);
  } else if(streak&&streak.type==='LOSS'&&streak.count>=2){
    dial+=5;
    reasoning.push(`${streak.count}L streak — dial +5 (slow down)`);
  }
  // Live volatility — same logic as the old auto-dial, but additive to schedule
  if(analysis){
    const _vr=analysis?.velocityRegime||'NORMAL';
    const _wa=analysis?.windowAmplitude?.label||'NORMAL';
    const _atr=Number(analysis?.atrBps)||0;
    if(_vr==='EXTREME'){dial-=15;reasoning.push('Velocity EXTREME — dial -15 (move fast)');}
    else if(_vr==='FAST'){dial-=8;reasoning.push('Velocity FAST — dial -8');}
    else if(_vr==='SLOW'){dial+=8;reasoning.push('Velocity SLOW — dial +8 (patient)');}
    if(_wa==='WILD'){dial-=8;reasoning.push('Amplitude WILD — dial -8');}
    else if(_wa==='WHIPSAW'){dial+=12;reasoning.push('Amplitude WHIPSAW — dial +12 (don\'t fight chop)');}
    else if(_wa==='DEAD'||_wa==='OPENING'){dial+=8;reasoning.push(`Amplitude ${_wa} — dial +8`);}
    if(_atr>0&&_atr<6){dial=Math.max(dial,55);reasoning.push('ATR <6bps (very tight) — floor dial at 55');}
    if(_atr>30){dial=Math.min(dial,40);reasoning.push('ATR >30bps (volatile) — ceiling dial at 40');}
  }
  // Today's actual WR adjustment — only if we have enough samples
  if(typeof todaySessionWR==='number'&&todaySessionN>=5){
    if(todaySessionWR<50){
      dial+=8;
      reasoning.push(`Today's session WR ${Math.round(todaySessionWR)}% (n=${todaySessionN}) — dial +8 (cool off)`);
    } else if(todaySessionWR>=80){
      dial+=5;
      reasoning.push(`Today's session WR ${Math.round(todaySessionWR)}% (n=${todaySessionN}) — dial +5 (lock in gains)`);
    }
  }
  // Clamp and snap to nearest 5
  dial=Math.max(0,Math.min(100,Math.round(dial/5)*5));
  return{dial,reasoning,status:_slot.status,scheduleNote:_slot.note,scheduleWR:_slot.wr,hour:_hour};
};

// ═══════════════════════════════════════════════════════════════════════════
// V9.15: LIVE PATTERN MATCHER (K-NEAREST HISTORICAL ANALOGS)
// ═══════════════════════════════════════════════════════════════════════════
// Given the current trade setup (regime, session, signal scores, etc.) finds
//   the K most-similar historical resolved trades and returns their outcome
//   distribution. Used as a second-opinion alongside the posterior.
//
// Approach: feature-vector cosine similarity. Each trade (current + historical)
//   becomes a normalized vector of ~16 dimensions. Cosine similarity ranges
//   -1 to 1; closer to 1 = more similar setup. Top K most-similar entries are
//   returned with their WIN/LOSS outcome.
//
// Why cosine vs euclidean: signals have different natural ranges (gap can be
//   ±55, ml is ±10, posterior is 0-100). Cosine compares DIRECTION of the
//   vector regardless of magnitude — so a "high-conviction UP setup" matches
//   other high-conviction UP setups whether magnitude is 50 or 80.
//
// Why not modify totalScore yet: V9.15 is OBSERVATIONAL. Per user direction,
//   the matcher exposes its findings to UI and to entry telemetry but doesn't
//   change lock decisions. After ~50 resolved trades on V9.15, we'll have data
//   on whether historical-analog WR predicts current outcome better than
//   posterior alone. If yes, V9.16 wires it into the engine.

// V9.15: feature extraction. Takes either a live `analysis` object (engine
//   output) OR a historical resolved entry and returns a normalized vector.
//   ORDER MATTERS — both sources must produce identically-shaped vectors.
//
// Returns: { vec: number[], dir: 'UP'|'DOWN'|null, valid: boolean }
//   valid: false if essential fields missing — entry should be excluded
const taraExtractMatchFeatures=(src,isLive)=>{
  // Live: src is the analysis object from useMemo. Historical: src is a trade-log entry.
  // We pull the SAME fields from each via a normalized accessor.
  let _dir,_regime,_session,_posterior,_atr,_sigs,_hour;
  if(isLive){
    // Live extraction from analysis object
    _dir=src?.lockInfo?.dir||(src?.rawProbAbove>50?'UP':src?.rawProbAbove<50?'DOWN':null);
    _regime=src?.regime||'';
    _session=src?.session||(typeof getMarketSessions==='function'?getMarketSessions().dominant:'')||'';
    _posterior=Number(src?.rawProbAbove)||50;
    _atr=Number(src?.atrBps)||0;
    _sigs=src?.rawSignalScores||{};
    _hour=new Date().getUTCHours();
  } else {
    // Historical extraction from resolved entry
    _dir=src?.dir||src?.direction||null;
    _regime=src?.regime||'';
    _session=src?.session||'';
    _posterior=Number(src?.posterior)||50;
    _atr=Number(src?.atrBpsAtLock)||0;
    _sigs=src?.signalScoresAtLock||{};
    _hour=new Date(src?.id||src?.time||Date.now()).getUTCHours();
  }
  // Validity check: need at minimum regime + session + signal scores
  if(!_regime||!_session||!_sigs||Object.keys(_sigs).length===0){
    return{vec:null,dir:_dir,valid:false};
  }
  // Build vector. ORDER MUST BE STABLE — changing this breaks similarity calc.
  const _regimes=['TRENDING UP','TRENDING DOWN','RANGE-CHOP','SHORT SQUEEZE','HIGH VOL CHOP'];
  const _sessions=['ASIA','EU','US','OFF-HOURS'];
  const vec=[];
  // Direction: ±1, 0 if null
  vec.push(_dir==='UP'?1:_dir==='DOWN'?-1:0);
  // Regime one-hot (5 dims)
  _regimes.forEach(r=>vec.push(_regime===r?1:0));
  // Session one-hot (4 dims)
  _sessions.forEach(s=>vec.push(_session===s?1:0));
  // Hour of day, sin/cos encoded (2 dims) — captures circularity of time
  const _hourRad=(_hour/24)*2*Math.PI;
  vec.push(Math.sin(_hourRad));
  vec.push(Math.cos(_hourRad));
  // Posterior normalized to [-1, 1] (50 = neutral)
  vec.push((Math.max(0,Math.min(100,_posterior))-50)/50);
  // ATR normalized — 30bps = 1.0 cap (typical high vol)
  vec.push(Math.min(1,_atr/30));
  // Signal scores — normalize each by typical max range
  // Most ±35, htfPatterns ±55, ml ±10, futures ±33
  const _normRanges={gap:35,momentum:35,structure:35,flow:35,technical:35,regime:35,rangePosition:35,
    htfPatterns:55,futures:33,ml:10,timeOfDay:10,macroShock:10,calendarRisk:35,tapeAccel:10,spotPerpDiv:8};
  ['gap','momentum','structure','flow','technical','regime','htfPatterns','futures','ml'].forEach(k=>{
    const _v=Number(_sigs[k])||0;
    const _max=_normRanges[k]||35;
    vec.push(Math.max(-1,Math.min(1,_v/_max)));
  });
  return{vec,dir:_dir,valid:true};
};

// V9.15: cosine similarity between two equal-length vectors. Returns [-1, 1].
const _taraCosineSim=(a,b)=>{
  if(!a||!b||a.length!==b.length)return 0;
  let dot=0,magA=0,magB=0;
  for(let i=0;i<a.length;i++){
    dot+=a[i]*b[i];
    magA+=a[i]*a[i];
    magB+=b[i]*b[i];
  }
  if(magA===0||magB===0)return 0;
  return dot/(Math.sqrt(magA)*Math.sqrt(magB));
};

// V9.15: main matcher. Takes current analysis + the historical trade log,
//   returns K nearest analogs with their outcomes + summary stats.
//
// Returns: {
//   topK: [{id, time, similarity, dir, result, posterior, regime, session}],
//   analogWR: number,         // % of topK that won
//   analogN: number,          // count of topK actually populated
//   analogConfidence: 'high' | 'medium' | 'low',  // based on similarity spread
//   avgSimilarity: number,    // mean cosine similarity of topK
//   currentDir: 'UP'|'DOWN'|null,
//   valid: bool,              // false if current feature vec couldn't be built
//   reason: string,           // explanation (for UI)
// }
const taraFindHistoricalAnalogs=(analysis,taraCallLog,currentAsset,K)=>{
  const _K=K||12;
  const _current=taraExtractMatchFeatures(analysis,true);
  if(!_current.valid){
    return{topK:[],analogWR:null,analogN:0,analogConfidence:'low',avgSimilarity:0,
      currentDir:_current.dir,valid:false,reason:'Current setup incomplete (no regime/session/signals)'};
  }
  // Build pool: all resolved trades of the same asset with valid feature vectors
  const _pool=[];
  (taraCallLog||[]).forEach(e=>{
    if(!e||(e.result!=='WIN'&&e.result!=='LOSS'))return;
    if((e.asset||'BTC')!==currentAsset)return;
    const _f=taraExtractMatchFeatures(e,false);
    if(!_f.valid)return;
    _pool.push({entry:e,feat:_f.vec});
  });
  if(_pool.length<10){
    return{topK:[],analogWR:null,analogN:0,analogConfidence:'low',avgSimilarity:0,
      currentDir:_current.dir,valid:false,reason:`Insufficient history (${_pool.length} valid entries, need ≥10)`};
  }
  // Compute similarity for each, sort desc
  const _scored=_pool.map(p=>({entry:p.entry,similarity:_taraCosineSim(_current.vec,p.feat)}));
  _scored.sort((a,b)=>b.similarity-a.similarity);
  const _top=_scored.slice(0,_K);
  // Outcome stats
  const _wins=_top.filter(t=>t.entry.result==='WIN').length;
  const _analogWR=_top.length>0?(_wins/_top.length)*100:null;
  const _avgSim=_top.length>0?_top.reduce((s,t)=>s+t.similarity,0)/_top.length:0;
  // Confidence in the match itself: high if top-K are all very similar (avg sim ≥0.85)
  //   AND there's a clean separation from the next batch. Medium if avg sim 0.70-0.85.
  //   Low if avg sim <0.70 (current setup isn't well represented in history).
  let _conf='low';
  if(_avgSim>=0.85)_conf='high';
  else if(_avgSim>=0.70)_conf='medium';
  return{
    topK:_top.map(t=>({
      id:t.entry.id||t.entry.time,
      time:t.entry.id||t.entry.time,
      similarity:t.similarity,
      dir:t.entry.dir||t.entry.direction,
      result:t.entry.result,
      posterior:t.entry.posterior,
      regime:t.entry.regime,
      session:t.entry.session,
      closingGapBps:t.entry.closingGapBps,
      tier:t.entry.tier,
    })),
    analogWR:_analogWR,
    analogN:_top.length,
    analogConfidence:_conf,
    avgSimilarity:_avgSim,
    currentDir:_current.dir,
    valid:true,
    reason:`${_top.length} of ${_pool.length} pool matches (avg sim ${_avgSim.toFixed(2)})`,
  };
};

// ═══════════════════════════════════════════════════════════════════════════
// V9.17: SCALPER ADVISOR — short-horizon Kalshi contract advisor
// ═══════════════════════════════════════════════════════════════════════════
// Separate engine from Tara's 15m posterior. Reads same raw feeds (tape, flow,
// futures, spot-perp, depth, velocity) but with weights tuned for 30-90 second
// holds and outputs Kalshi-cents-native recommendations.
//
// Tara's lock system is UNTOUCHED. The scalper runs in parallel:
//   - Tara: 15m window posterior → lock decision → optional auto-exec
//   - Scalper: continuous short-horizon read → contract entry/exit advisor
//
// Storage: taraScalperLog_v1 (localStorage). Never writes to taraCallLog or
//   taraScorecards. Has its own learning loop (not yet built — first ship is
//   stateless engine + manual logging).
//
// State machine:
//   IDLE → SUGGEST → user enters → HOLD → exit conditions → COOLDOWN → IDLE
// Anti-tilt: when Tara's tiltLockUntil is active, scalper inherits same block.
// Daily contract loss cap: when sum of losses (cents) ≥ limit, stop until next UTC day.
// Hourly suggestion cap: max N new suggestions per rolling 60min window.
// Weak hours: 12-17 EST blocked by default (matches V9.13 schedule).
//
// All thresholds user-configurable via TARA_SCALPER_DEFAULTS overrides stored
// in localStorage as taraScalperSettings_v1.

// V9.17: scalper settings defaults
// V9.17.2: auto-exec removed — scalper is advisory only.
// V9.17.3: auto-exec re-added with mutual exclusivity with Tara's auto-exec.
//          Conflict guard kept for safety. Auto-detect placeholder NOT re-added
//          (still no kalshiGetPositions REST helper; manual entry/exit is the path).
const TARA_SCALPER_DEFAULTS={
  enabled:false, // start OFF — user must opt in
  // Entry zones (YES side cents range we're willing to suggest)
  entryMinCents:15,
  entryMaxCents:45,
  // Target / stop (cents from entry)
  targetCents:35,
  stopCents:15,
  // Sizing
  contractsPerScalp:1,
  // Caps
  dailyLossCapCents:200,
  maxSuggestionsPerHour:3,
  // Cooldowns (minutes)
  cooldownAfterLossMin:30,
  cooldownAfterProfitMin:5,
  cooldownAfterNeutralMin:10,
  cooldownFloorMin:0, // no floor — user fully controls
  // Hours blocked (24-hour EST). Empty array = no block.
  blockHoursEst:[12,13,14,15,16,17],
  // V9.17.3: Auto-execution (back, mutually exclusive with Tara's auto-exec)
  autoExecEnabled:false, // start OFF
  conflictGuardEnabled:true, // when ON, scalper auto-exec also blocked if Tara has locked position on same market
  // Conviction threshold for SUGGEST
  minConviction:65,
};

// V9.17: load/save scalper settings
const loadScalperSettings=()=>{
  try{
    const s=localStorage.getItem('taraScalperSettings_v1');
    if(s){
      const parsed=JSON.parse(s);
      return{...TARA_SCALPER_DEFAULTS,...parsed};
    }
  }catch(_){}
  return{...TARA_SCALPER_DEFAULTS};
};
const saveScalperSettings=(s)=>{
  try{localStorage.setItem('taraScalperSettings_v1',JSON.stringify(s||{}));}catch(_){}
};

// V9.17: load/save scalper trade log
const loadScalperLog=()=>{
  try{
    const s=localStorage.getItem('taraScalperLog_v1');
    if(s){
      const parsed=JSON.parse(s);
      if(Array.isArray(parsed))return parsed;
    }
  }catch(_){}
  return[];
};
const saveScalperLog=(log)=>{
  try{localStorage.setItem('taraScalperLog_v1',JSON.stringify(Array.isArray(log)?log:[]));}catch(_){}
};

// V9.17: SCALPER ENGINE — computes short-horizon directional read and conviction.
//   Inputs: same raw feeds Tara uses, but reweighted for 30-90s horizon.
//   Output: { dir, conviction, reason, signals } — pure, no state.
//
// Signal weights (different from Tara's 15m engine):
//   - tapeAccel (5s vs 30s buy% divergence): PRIMARY ±30
//   - flow (30s aggressor imbalance): PRIMARY ±25
//   - velocity (tick momentum): ±15
//   - spotPerpDiv (perp premium/discount, contrarian): ±10
//   - depthFlash (order book pressure): ±10
//   - macroShock (4-asset coordination): ±10 (additive when present)
//   - tape consensus (w5/w15/w30 alignment): ±10
// Sum capped at ±100; conviction = abs(score).
//
// NOT included:
//   - gap (Kalshi-specific, irrelevant to spot direction)
//   - momentum / regime / htfPatterns (too slow for scalp horizon)
//   - ml model (trained on 15m outcomes)
const computeScalperRead=(inputs)=>{
  const{tapeWindows,globalFlow,velocityRef,spotPerpDiv,depthFlash,macroShockData,currentAsset}=inputs||{};
  if(!tapeWindows||!tapeWindows.w5||!tapeWindows.w30){
    return{dir:null,conviction:0,reason:'Tape data not ready',signals:{},score:0};
  }
  let score=0;
  const sigs={};
  const reasons=[];
  // 1. TAPE ACCEL — primary signal. Recent (5s) buyPct vs medium (30s).
  const _w5=tapeWindows.w5,_w15=tapeWindows.w15||{},_w30=tapeWindows.w30;
  const _w5Total=(_w5.buys||0)+(_w5.sells||0);
  const _w30Total=(_w30.buys||0)+(_w30.sells||0);
  if(_w5Total>=10000&&_w30Total>=30000){
    const _w5Pct=_w5.buyPct||50;
    const _w30Pct=_w30.buyPct||50;
    const _diff=_w5Pct-_w30Pct;
    if(Math.abs(_diff)>=10){
      const _mag=Math.min(30,Math.tanh(Math.abs(_diff)/25)*30);
      const _dir=_diff>0?1:-1;
      sigs.tapeAccel=_mag*_dir;
      score+=_mag*_dir;
      reasons.push(`tape ${_diff>0?'accelerating up':'accelerating down'} (5s ${_w5Pct.toFixed(0)}% vs 30s ${_w30Pct.toFixed(0)}%)`);
    }
  }
  // 2. FLOW — 30s aggressor imbalance. globalFlow.imbalance is ratio (1.0 = neutral, >1 = buy-dom, <1 = sell-dom)
  if(globalFlow&&typeof globalFlow.imbalance==='number'){
    const _aggr=Math.max(-1,Math.min(1,globalFlow.imbalance-1));
    if(Math.abs(_aggr)>=0.15){
      const _mag=Math.min(25,Math.abs(_aggr)*30);
      const _dir=_aggr>0?1:-1;
      sigs.flow=_mag*_dir;
      score+=_mag*_dir;
      reasons.push(`flow ${_aggr>0?'bullish':'bearish'} (imbalance ${_aggr.toFixed(2)})`);
    }
  }
  // 3. VELOCITY — recent tick momentum. velocityRef.current is signed value
  if(velocityRef&&velocityRef.current){
    const _vel=Number(velocityRef.current.bps1s)||0;
    if(Math.abs(_vel)>=0.5){
      const _mag=Math.min(15,Math.abs(_vel)*8);
      const _dir=_vel>0?1:-1;
      sigs.velocity=_mag*_dir;
      score+=_mag*_dir;
      reasons.push(`velocity ${_vel>0?'+':''}${_vel.toFixed(1)}bps/s`);
    }
  }
  // 4. SPOT-PERP DIVERGENCE — contrarian. perp premium = shorts squeeze risk for shorts
  if(spotPerpDiv&&spotPerpDiv.status==='live'&&Math.abs(spotPerpDiv.divBps)>=20){
    const _mag=Math.min(10,(Math.abs(spotPerpDiv.divBps)-20)*0.15+4);
    // CONTRARIAN: perp premium (positive) → DOWN bias (longs vulnerable)
    const _dir=spotPerpDiv.divBps>0?-1:1;
    sigs.spotPerpDiv=_mag*_dir;
    score+=_mag*_dir;
    reasons.push(`spot/perp ${spotPerpDiv.divBps>0?'longs crowded':'shorts crowded'} (${Math.round(spotPerpDiv.divBps)}bps)`);
  }
  // 5. DEPTH FLASH — order book pressure
  if(depthFlash&&depthFlash.signal){
    const _flashScore=Number(depthFlash.score)||0;
    if(Math.abs(_flashScore)>=3){
      const _mag=Math.min(10,Math.abs(_flashScore)*1.5);
      const _dir=_flashScore>0?1:-1;
      sigs.depth=_mag*_dir;
      score+=_mag*_dir;
      reasons.push(`book ${_flashScore>0?'bid-heavy':'ask-heavy'}`);
    }
  }
  // 6. MACRO SHOCK — 4-asset coordination
  if(macroShockData&&macroShockData.status==='live'){
    const _sol=macroShockData.sol?.deltaBps||0;
    const _xrp=macroShockData.xrp?.deltaBps||0;
    if(Math.abs(_sol)>=30&&Math.abs(_xrp)>=30&&Math.sign(_sol)===Math.sign(_xrp)){
      const _mag=Math.min(10,(Math.abs(_sol)+Math.abs(_xrp))/12);
      const _dir=_sol>0?1:-1;
      sigs.macroShock=_mag*_dir;
      score+=_mag*_dir;
      reasons.push(`macro shock ${_dir>0?'up':'down'} (sol+xrp aligned)`);
    }
  }
  // 7. TAPE CONSENSUS — w5/w15/w30 all agreeing
  if(_w5Total>=10000&&_w15&&_w30Total>=30000){
    const _w5p=_w5.buyPct||50,_w15p=_w15.buyPct||50,_w30p=_w30.buyPct||50;
    if(_w5p>=60&&_w15p>=60&&_w30p>=60){
      sigs.tapeConsensus=10;score+=10;
      reasons.push('tape consensus all timeframes UP');
    } else if(_w5p<=40&&_w15p<=40&&_w30p<=40){
      sigs.tapeConsensus=-10;score-=10;
      reasons.push('tape consensus all timeframes DOWN');
    }
  }
  // Cap and direction
  score=Math.max(-100,Math.min(100,score));
  const conviction=Math.round(Math.abs(score));
  const dir=Math.abs(score)<8?null:(score>0?'UP':'DOWN');
  return{
    dir,conviction,score,signals:sigs,
    reason:reasons.length>0?reasons.join(' · '):'No clear short-horizon signals',
  };
};

// V9.17: utility — get current EST hour with DST approximation
const _scalperGetEstHour=()=>{
  const d=new Date();
  const _month=d.getUTCMonth();
  const _dstActive=_month>=2&&_month<=10;
  const _offset=_dstActive?4:5;
  return((d.getUTCHours()-_offset)+24)%24;
};

// V9.17: cooldown helpers — when did we last EXIT a scalp, and what was the result?
const _scalperGetActiveCooldown=(scalperLog,settings)=>{
  if(!Array.isArray(scalperLog)||scalperLog.length===0)return null;
  const _last=scalperLog[scalperLog.length-1];
  if(!_last||!_last.exitTime)return null;
  const _ageMs=Date.now()-_last.exitTime;
  const _ageMin=_ageMs/60000;
  let _required=0;
  if(_last.outcome==='LOSS')_required=Math.max(settings.cooldownFloorMin||0,settings.cooldownAfterLossMin||0);
  else if(_last.outcome==='WIN')_required=Math.max(settings.cooldownFloorMin||0,settings.cooldownAfterProfitMin||0);
  else if(_last.outcome==='NEUTRAL')_required=Math.max(settings.cooldownFloorMin||0,settings.cooldownAfterNeutralMin||0);
  if(_required<=0||_ageMin>=_required)return null;
  const _remainingSec=Math.max(0,Math.ceil((_required*60)-_ageMs/1000));
  return{
    activeUntil:_last.exitTime+_required*60000,
    remainingSec:_remainingSec,
    reason:_last.outcome==='LOSS'?'loss cooldown (revenge-trading prevention)'
      :_last.outcome==='WIN'?'profit cooldown (don\'t chase the heat)'
      :'neutral cooldown',
    lastOutcome:_last.outcome,
  };
};

// V9.17: hourly suggestion cap check — count suggestions emitted in the last 60min
const _scalperGetHourlyCount=(scalperLog,suggestionsLogRef)=>{
  // suggestionsLogRef is an in-memory ref tracking SUGGEST timestamps (cleared on UTC rollover)
  const _now=Date.now();
  const _oneHourAgo=_now-60*60*1000;
  const _suggestions=(suggestionsLogRef?.current||[]).filter(t=>t>=_oneHourAgo);
  return _suggestions.length;
};

// V9.17: today's daily loss check (UTC day boundary)
const _scalperGetTodayLossCents=(scalperLog)=>{
  const _now=new Date();
  const _utcMidnight=Date.UTC(_now.getUTCFullYear(),_now.getUTCMonth(),_now.getUTCDate());
  if(!Array.isArray(scalperLog))return 0;
  let _lossCents=0;
  scalperLog.forEach(e=>{
    if(!e||!e.exitTime)return;
    if(e.exitTime<_utcMidnight)return;
    if(e.outcome==='LOSS'&&typeof e.profitCents==='number'){
      _lossCents+=Math.abs(e.profitCents);
    }
  });
  return _lossCents;
};

// V9.17: today's stats summary for the UI footer
const computeScalperTodayStats=(scalperLog)=>{
  const _now=new Date();
  const _utcMidnight=Date.UTC(_now.getUTCFullYear(),_now.getUTCMonth(),_now.getUTCDate());
  let wins=0,losses=0,neutrals=0,netCents=0;
  (scalperLog||[]).forEach(e=>{
    if(!e||!e.exitTime||e.exitTime<_utcMidnight)return;
    if(e.outcome==='WIN'){wins++;netCents+=e.profitCents||0;}
    else if(e.outcome==='LOSS'){losses++;netCents+=e.profitCents||0;} // profitCents is negative for losses
    else if(e.outcome==='NEUTRAL'){neutrals++;netCents+=e.profitCents||0;}
  });
  const n=wins+losses+neutrals;
  return{wins,losses,neutrals,n,netCents,winRate:n>0?Math.round((wins/n)*100):null};
};

// V9.17: compute eligibility for emitting a new SUGGEST
//   Returns: { eligible, blockReason } — blockReason is human-readable when blocked
const checkScalperEligibility=({settings,scalperLog,suggestionsLogRef,tiltLockUntil,kalshiYesPrice})=>{
  if(!settings.enabled)return{eligible:false,blockReason:'scalper disabled in settings'};
  // Anti-tilt inheritance from Tara
  if(tiltLockUntil&&Date.now()<tiltLockUntil){
    const _remainSec=Math.ceil((tiltLockUntil-Date.now())/1000);
    return{eligible:false,blockReason:`tara anti-tilt active · ${Math.floor(_remainSec/60)}m ${_remainSec%60}s remaining`};
  }
  // Weak hours block
  const _hour=_scalperGetEstHour();
  if(Array.isArray(settings.blockHoursEst)&&settings.blockHoursEst.includes(_hour)){
    return{eligible:false,blockReason:`weak hour block · ${_hour}:00 EST is in your skip window`};
  }
  // Cooldown from last trade
  const _cd=_scalperGetActiveCooldown(scalperLog,settings);
  if(_cd){
    const _m=Math.floor(_cd.remainingSec/60),_s=_cd.remainingSec%60;
    return{eligible:false,blockReason:`${_cd.reason} · ${_m}:${_s.toString().padStart(2,'0')} remaining`,cooldown:_cd};
  }
  // Hourly suggestion cap
  const _hourly=_scalperGetHourlyCount(scalperLog,suggestionsLogRef);
  if(_hourly>=(settings.maxSuggestionsPerHour||3)){
    return{eligible:false,blockReason:`hourly cap reached · ${_hourly}/${settings.maxSuggestionsPerHour} suggestions this hour`};
  }
  // Daily loss cap
  const _todayLoss=_scalperGetTodayLossCents(scalperLog);
  if(_todayLoss>=(settings.dailyLossCapCents||200)){
    return{eligible:false,blockReason:`daily loss cap hit · -${_todayLoss}¢ today (limit ${settings.dailyLossCapCents}¢)`};
  }
  // YES price in entry zone
  if(typeof kalshiYesPrice!=='number'||kalshiYesPrice<=0){
    return{eligible:false,blockReason:'kalshi yes price not available'};
  }
  // We check whether the suggested direction's entry will fall in the configured zone in the engine;
  //   here we just confirm a price exists. Final zone check happens in advisor below.
  return{eligible:true};
};

// V9.17: useScalperEngine hook. Runs every 1s, computes scalper read.
//   Returns the latest `computeScalperRead` output.
const useScalperEngine=({tapeWindows,globalFlow,velocityRef,spotPerpDiv,depthFlash,macroShockData,currentAsset,enabled})=>{
  const[read,setRead]=React.useState({dir:null,conviction:0,score:0,signals:{},reason:''});
  React.useEffect(()=>{
    if(!enabled)return;
    const _tick=()=>{
      const r=computeScalperRead({tapeWindows,globalFlow,velocityRef,spotPerpDiv,depthFlash,macroShockData,currentAsset});
      setRead(r);
    };
    _tick();
    const iv=setInterval(_tick,1000);
    return()=>clearInterval(iv);
  },[enabled,tapeWindows,globalFlow,velocityRef,spotPerpDiv,depthFlash,macroShockData,currentAsset]);
  return read;
};

// ═══════════════════════════════════════════════════════════════════════════
// V9.17.4: KALSHI PORTFOLIO BALANCE TRACKING
// ═══════════════════════════════════════════════════════════════════════════
// Polls /portfolio/balance every 30s when credentials exist. Captures a
// session baseline at first successful poll, persists baseline per-UTC-day
// so "today's delta" survives reloads (resets at UTC midnight).
//
// State shape: { balance, baseline, baselineDay, lastFetchAt, status, error }
//   - balance: current Kalshi balance in dollars (cents/100)
//   - baseline: balance at start of UTC day
//   - baselineDay: UTC date string for baseline (YYYY-MM-DD)
//   - lastFetchAt: timestamp of last successful poll
//   - status: 'idle' | 'connected' | 'error' | 'no-creds'
//
// "Today's delta" = balance - baseline. If baselineDay !== today, reset baseline.
const useKalshiBalance=({kalshiCreds,timeFormat})=>{
  const[state,setState]=React.useState(()=>{
    try{
      const saved=JSON.parse(localStorage.getItem('tara_kalshi_balance_v1')||'{}');
      return{
        balance:typeof saved.balance==='number'?saved.balance:null,
        baseline:typeof saved.baseline==='number'?saved.baseline:null,
        baselineDay:saved.baselineDay||null,
        lastFetchAt:saved.lastFetchAt||0,
        status:'idle',
        error:null,
      };
    }catch(_){
      return{balance:null,baseline:null,baselineDay:null,lastFetchAt:0,status:'idle',error:null};
    }
  });
  React.useEffect(()=>{
    try{
      localStorage.setItem('tara_kalshi_balance_v1',JSON.stringify({
        balance:state.balance,baseline:state.baseline,baselineDay:state.baselineDay,lastFetchAt:state.lastFetchAt,
      }));
    }catch(_){}
  },[state.balance,state.baseline,state.baselineDay,state.lastFetchAt]);
  React.useEffect(()=>{
    if(!kalshiCreds?.apiKeyId||!kalshiCreds?.privateKeyPem){
      setState(prev=>({...prev,status:'no-creds'}));
      return;
    }
    let _cancelled=false;
    const _poll=async()=>{
      try{
        const res=await kalshiPing({apiKeyId:kalshiCreds.apiKeyId,privateKeyPem:kalshiCreds.privateKeyPem});
        if(_cancelled)return;
        if(!res.ok){
          setState(prev=>({...prev,status:'error',error:res.reason||'unknown'}));
          return;
        }
        // Kalshi returns balance in cents (integer). Convert to dollars.
        const _rawBalance=Number(res.balance);
        if(!Number.isFinite(_rawBalance)){
          setState(prev=>({...prev,status:'error',error:'invalid-balance'}));
          return;
        }
        const _balanceDollars=_rawBalance/100;
        const _today=_dayKey(new Date(),timeFormat); // V10.2.x: honors header TZ (was UTC-only)
        setState(prev=>{
          // Reset baseline on new day (in user's TZ) OR if no baseline exists yet.
          // V9.17.9: was `!_baseline` which is true for 0, causing baseline to
          //   reset every poll when actual balance was zero. Use typeof check.
          let _baseline=prev.baseline;
          let _baselineDay=prev.baselineDay;
          if(typeof _baseline!=='number'||_baselineDay!==_today){
            _baseline=_balanceDollars;
            _baselineDay=_today;
          }
          return{
            balance:_balanceDollars,
            baseline:_baseline,
            baselineDay:_baselineDay,
            lastFetchAt:Date.now(),
            status:'connected',
            error:null,
          };
        });
      }catch(e){
        if(_cancelled)return;
        setState(prev=>({...prev,status:'error',error:e?.message||String(e)}));
      }
    };
    _poll();
    const iv=setInterval(_poll,30000);
    return()=>{_cancelled=true;clearInterval(iv);};
  },[kalshiCreds?.apiKeyId,kalshiCreds?.privateKeyPem,timeFormat]); // V10.2.x: timeFormat in deps so day-roll re-evaluates
  return state;
};

// V9.2.3: TIME-OF-DAY MODEL — computes hourly WR from call log, returns a
//   boost/penalty map keyed by UTC hour. Fed into the engine posterior.
const computeTimeOfDayModel=(log,asset)=>{
  const hourStats={};
  for(let h=0;h<24;h++)hourStats[h]={W:0,L:0};
  (log||[]).forEach(e=>{
    if(!e||!e.result||(e.asset||'BTC')!==asset)return;
    if(e.result!=='WIN'&&e.result!=='LOSS')return;
    const dt=new Date(e.id||e.time);
    const h=dt.getUTCHours();
    if(e.result==='WIN')hourStats[h].W++;else hourStats[h].L++;
  });
  // Compute per-hour boost: WR > 60% → positive, WR < 45% → negative. Needs ≥8 trades.
  const boostMap={};
  for(let h=0;h<24;h++){
    const n=hourStats[h].W+hourStats[h].L;
    if(n<8){boostMap[h]=0;continue;}
    const wr=hourStats[h].W/n;
    if(wr>=0.70)boostMap[h]=6;
    else if(wr>=0.60)boostMap[h]=3;
    else if(wr>=0.55)boostMap[h]=1;
    else if(wr>=0.45)boostMap[h]=0;
    else if(wr>=0.35)boostMap[h]=-3;
    else boostMap[h]=-6;
  }
  return boostMap;
};

const formatDuration=(seconds)=>{
  if(seconds==null||isNaN(seconds))return'—';
  const s=Math.max(0,Math.round(seconds));
  if(s<60)return`${s}s`;
  const m=Math.floor(s/60);
  const r=s%60;
  return`${m}m ${String(r).padStart(2,'0')}s`;
};
// V5.7.3: Stable signed-integer formatter — fixes -0 / +0 weirdness in score breakdowns.
const formatSignedInt=(val)=>{
  if(val==null||isNaN(val))return'0';
  const r=Math.round(val);
  if(r===0)return'0';
  return(r>0?'+':'')+r;
};
const calcVWAP=(h)=>{if(!h||!h.length)return null;let t=0,v=0;h.forEach(c=>{t+=((c.h+c.l+c.c)/3)*c.v;v+=c.v;});return v===0?null:t/v;};
const calcRSI=(d,p=14)=>{if(!d||d.length<p+1)return 50;let ag=0,al=0;for(let i=1;i<=p;i++){const x=d[i-1]-d[i];if(x>0)ag+=x;else al-=x;}ag/=p;al/=p;for(let i=p+1;i<Math.min(d.length,p+30);i++){const x=d[i-1]-d[i];ag=(ag*(p-1)+Math.max(x,0))/p;al=(al*(p-1)+Math.max(-x,0))/p;}return al===0?100:100-(100/(1+(ag/al)));};
const calcATR=(h,p=14)=>{if(!h||h.length<p+1)return 0;let s=0;for(let i=0;i<p;i++){const H=h[i].h,L=h[i].l,pc=h[i+1]?.c||h[i].o;s+=Math.max(H-L,Math.abs(H-pc),Math.abs(L-pc));}return s/p;};
const calcBB=(c,p=20)=>{if(!c||c.length<p)return{upper:0,mid:0,lower:0,pctB:0.5,width:0};const s=c.slice(0,p),m=s.reduce((a,b)=>a+b,0)/p,sd=Math.sqrt(s.reduce((a,b)=>a+Math.pow(b-m,2),0)/p);const u=m+2*sd,l=m-2*sd;return{upper:u,mid:m,lower:l,pctB:(u-l)>0?(c[0]-l)/(u-l):0.5,width:m>0?((u-l)/m)*10000:0};};

// V99 NEW INDICATORS
const calcConsecutiveCandles=(history)=>{if(!history||history.length<2)return{green:0,red:0};let green=0,red=0;for(const c of history){if(c.c>c.o){if(red>0)break;green++;}else if(c.c<c.o){if(green>0)break;red++;}else break;}return{green,red};};
const calcVolumeRatio=(history,recent=5,baseline=25)=>{if(!history||history.length<baseline)return 1;const rv=history.slice(0,recent).reduce((s,c)=>s+(c.v||0),0)/recent;const bv=history.slice(recent,baseline).reduce((s,c)=>s+(c.v||0),0)/(baseline-recent);return bv>0?rv/bv:1;};
const calcPriceChannel=(history,n=20)=>{if(!history||history.length<n)return 0.5;const hi=Math.max(...history.slice(0,n).map(c=>c.h));const lo=Math.min(...history.slice(0,n).map(c=>c.l));return hi>lo?(history[0].c-lo)/(hi-lo):0.5;};
const calcMomentumAlignment=(d1,d5,d15)=>{const signs=[Math.sign(d1),Math.sign(d5),Math.sign(d15)];const sum=signs.reduce((a,b)=>a+b,0);if(Math.abs(sum)===3)return{aligned:true,strong:true,dir:sum>0?1:-1};if(Math.abs(sum)>=2)return{aligned:true,strong:false,dir:sum>0?1:-1};return{aligned:false,strong:false,dir:0};};

// ═══════════════════════════════════════
// TARA SELF-TRAINING ENGINE V1
// Adaptive weights + calibration + trade log
// ═══════════════════════════════════════

// Default signal weights — trained on 268-trade dataset
// 163W-105L=60.8% · UP 65% · DOWN 55.6% · SS 68% · TD 87.5% · EU 69.7%
// DOWN in SHORT SQUEEZE: 50% — regime-gated suppression active
// V152: Added rangePosition — mean-reversion / range-exhaustion signal.
// Measures how far we've drifted from window-open price relative to ATR-scaled envelope.
// V4.6 FRESH START: Default weights reset to neutral midpoint. Per user request — full
//   training reset, no carryover from the 57-trade seed CSV. Each signal starts at the
//   same weight so gradient descent learns purely from the user's live trades.
const DEFAULT_WEIGHTS={gap:35.00,momentum:35.00,structure:35.00,flow:35.00,technical:35.00,regime:35.00,rangePosition:35.00,
  // V9.11.0: htfPatterns and futures are MULTIPLIERS, not raw weights. The underlying
  //   signal values are already pre-weighted inside their detector logic (chart patterns
  //   contribute ±20 internally, etc.). The learning loop adjusts these multipliers up
  //   or down based on observed win/loss attribution. Default 1.0 = neutral.
  //   Bounds [0.0, 2.5] mean a signal can be fully muted by learning if it consistently
  //   leads to losses, or buffed up to 2.5x if it's reliably right.
  htfPatterns:1.00,futures:1.00,
  // V9.12: macroShock is also a multiplier — raw signal already produces ±10. The
  //   weight learning loop tunes how much that ±10 nudge influences the final score.
  //   Starts neutral; if 4-asset shocks reliably predict outcome direction, it'll buff
  //   toward 2.5; if not, decay toward 0.
  macroShock:1.00,
  // V9.14: three new signals, each a multiplier on its respective raw output.
  //   - calendarRisk: dampener during macro events, default 1.0 means apply ±25-35 as-is
  //   - tapeAccel: ±10 raw, multiplier tunes effective strength
  //   - spotPerpDiv: ±8 raw, multiplier tunes effective strength
  calendarRisk:1.00,tapeAccel:1.00,spotPerpDiv:1.00};

// Per-regime weight sets — each regime gets its own gradient descent
// Initialized from global defaults, diverge over time based on what works in each regime
// V143: Per-regime weight defaults pre-trained from 379 seed trades. Previously all four
//       regimes started from identical DEFAULT_WEIGHTS — gradient descent was supposed to
//       differentiate them over time but the attribution gate (>10%) + small learning rate
//       produced ~1-3pt deltas after hundreds of trades. Pre-baking the seed-trained values
//       gives users a differentiated starting point on first load. Subsequent live trades
//       continue to update via gradient descent on top.
// V4.6 FRESH START: Per-regime weights reset to neutral. All four regimes start identical
//   from DEFAULT_WEIGHTS — gradient descent will differentiate them as you trade.
const DEFAULT_REGIME_WEIGHTS={
  'SHORT SQUEEZE': {...DEFAULT_WEIGHTS},
  'RANGE-CHOP':    {...DEFAULT_WEIGHTS},
  'HIGH VOL CHOP': {...DEFAULT_WEIGHTS},
  'TRENDING DOWN': {...DEFAULT_WEIGHTS},
};
const REGIME_WEIGHT_KEYS={'SHORT SQUEEZE':'taraV110RW_SS_V110','RANGE-CHOP':'taraV110RW_RC_V110','HIGH VOL CHOP':'taraV110RW_HVC_V110','TRENDING DOWN':'taraV110RW_TD_V110'};
const loadRegimeWeights=()=>{
  const out={};
  Object.entries(REGIME_WEIGHT_KEYS).forEach(([rg,key])=>{
    try{const s=localStorage.getItem(key);if(s){const w=JSON.parse(s);if(w&&typeof w.gap==='number'){out[rg]=w;return;}}}catch(e){}
    out[rg]={...DEFAULT_REGIME_WEIGHTS[rg]};
  });
  return out;
};
// V5.5b: User-trade persistence stubbed per user request:
//   'stats and training records for Tara's calls needs to be saved only, not the ones i
//    take from predictor'.
//   - saveRegimeWeights: was learning per-regime weights from user trades → no-op
//   - saveTradeLog (below at line ~136): was user trade history → no-op
//   In-memory state still updates during a session so existing logic doesn't break.
//   Tara's Call scorecards (taraCallScorecards_v1) remain persisted independently.
// V7.8: User asked "why dont weights persist over sessions and why do we start clean".
//   Answer: V5.5b stubbed weight save when learning fed from USER trades (those polluted
//   weights). After V7.1's applyTradeLearning refactor, learning feeds EXCLUSIVELY from
//   Tara's own resolved calls (asset-tagged). That's exactly what should train weights.
//   So saveWeights is re-enabled to localStorage; cloud sync handled at the per-asset
//   state level (adaptiveWeightsByAsset / regimeWeightsByAsset) below.
const saveRegimeWeights=(rwObj)=>{
  try{localStorage.setItem('taraRegimeWeights_v1',JSON.stringify(rwObj||{}));}catch(e){}
};
const WEIGHT_BOUNDS={gap:[5,65],momentum:[5,58],structure:[2,38],flow:[2,55],technical:[5,48],regime:[2,45],rangePosition:[5,55],
  // V9.11.0: multiplier bounds. 0 means signal is fully muted; 2.5 means 250% amplified.
  htfPatterns:[0.00,2.50],futures:[0.00,2.50],
  // V9.12: macroShock multiplier bounds match htfPatterns/futures.
  macroShock:[0.00,2.50],
  // V9.14: calendar risk has tighter bounds (0.5-1.5) because we want the
  //   dampener to ALWAYS partially fire near macro events even if learning thinks
  //   it doesn't help — the cost of a single FOMC-spike loss outweighs marginal
  //   WR optimization. tapeAccel and spotPerpDiv use standard 0-2.5 bounds.
  calendarRisk:[0.50,1.50],tapeAccel:[0.00,2.50],spotPerpDiv:[0.00,2.50]};
const LEARNING_RATE=0.8;

const loadWeights=()=>{try{const s=localStorage.getItem('taraWeightsV110');if(s){const w=JSON.parse(s);if(w&&typeof w.gap==='number')return w;}return{...DEFAULT_WEIGHTS};}catch(e){return{...DEFAULT_WEIGHTS};}};
const saveWeights=(w)=>{
  try{localStorage.setItem('taraWeightsV110',JSON.stringify(w||{}));}catch(e){}
};

